  ['What Are Stocks','How Exchanges Work','Bull Markets','Bear Markets','Chart Types','Candle Anatomy','Bullish Candles','Support Levels','Volume Basics','SMA Explained','EMA & Crossovers','Stop-Loss Orders','Position Sizing','Risk-Reward Ratio','Market Cycles'].forEach(m => ensureLesson('Trading', m));

