  LESSON_QUESTIONS['Trading']['Margin Trading'] = [
    { type: 'multiple_choice', prompt: 'What is margin trading?', options: ['Trading with no money', 'Borrowing money from your broker to buy more securities than your cash allows', 'Trading on the margins of a chart', 'A type of paper trading'], correctAnswer: 'Borrowing money from your broker to buy more securities than your cash allows', difficulty: 'easy', explanation: 'Margin trading uses leverage — you borrow funds from your broker to increase your buying power. For example, with 2:1 margin, $10,000 in cash lets you control $20,000 worth of securities.' },
    { type: 'true_false', prompt: 'Margin amplifies both gains and losses.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'This is the double-edged sword of margin. If you buy $20,000 of stock with $10,000 cash and it rises 10%, you make $2,000 (20% on your capital). But a 10% drop also means a $2,000 loss (20% of your capital).' },
    { type: 'multiple_choice', prompt: 'What is a margin call?', options: ['A phone call from your broker to discuss new stocks', 'A demand from your broker to deposit more funds because your account equity has fallen below the maintenance requirement', 'A call option bought on margin', 'When the market calls a timeout'], correctAnswer: 'A demand from your broker to deposit more funds because your account equity has fallen below the maintenance requirement', difficulty: 'medium', explanation: 'When losses reduce your account equity below the maintenance margin (typically 25-30%), your broker issues a margin call. You must deposit more funds or the broker will liquidate your positions to cover the shortfall.' },
    { type: 'fill_gap', prompt: 'The initial margin requirement for stocks in the US is typically ___% of the purchase price.', options: ['50', '25', '10', '75'], correctAnswer: '50', difficulty: 'medium', explanation: 'Under Regulation T, the Federal Reserve requires a minimum initial margin of 50%, meaning you must put up at least half the value of the securities you buy. Brokers may require more for volatile stocks.' },
    { type: 'true_false', prompt: 'If you fail to meet a margin call, your broker can sell your positions without your permission.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'When you sign a margin agreement, you authorize the broker to liquidate your holdings if you cannot meet a margin call. The broker can sell any positions at any time to bring the account back to compliance.' },
    { type: 'multiple_choice', prompt: 'What is the maintenance margin?', options: ['The fee to maintain a brokerage account', 'The minimum equity percentage you must keep in your margin account after the initial purchase', 'The margin on your profit', 'The initial deposit required'], correctAnswer: 'The minimum equity percentage you must keep in your margin account after the initial purchase', difficulty: 'medium', explanation: 'Maintenance margin is the minimum account equity (typically 25-30%) that must be maintained at all times. If your equity drops below this level due to losses, a margin call is triggered.' },
    { type: 'swipe_judge', prompt: 'Using maximum leverage on a volatile penny stock.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'Maximum leverage on a volatile stock is extremely risky. A small adverse move can wipe out your entire account and potentially leave you owing money to your broker.' },
    { type: 'true_false', prompt: 'You pay interest on money borrowed through margin, which reduces your overall returns.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'hard', explanation: 'Margin loans accrue interest daily. At typical rates of 6-10% annually, the interest cost can significantly eat into profits, especially for longer holding periods. This is a cost many beginners overlook.' },
  ];

  LESSON_QUESTIONS['Trading']['Short Selling'] = [
    { type: 'multiple_choice', prompt: 'What is short selling?', options: ['Selling a stock you own', 'Borrowing shares and selling them, hoping to buy them back at a lower price to profit from a decline', 'Selling only a few shares', 'Trading for a short time period'], correctAnswer: 'Borrowing shares and selling them, hoping to buy them back at a lower price to profit from a decline', difficulty: 'easy', explanation: 'Short selling lets you profit from falling prices. You borrow shares from your broker, sell them at the current price, then aim to buy them back cheaper and return them, pocketing the difference.' },
    { type: 'true_false', prompt: 'Short selling has theoretically unlimited loss potential because a stock can rise indefinitely.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'When you buy a stock, the maximum you can lose is 100% (it goes to zero). But when you short, the stock can rise 200%, 500%, or more — there is no ceiling, making potential losses unlimited.' },
    { type: 'multiple_choice', prompt: 'What is a "short squeeze"?', options: ['When a heavily shorted stock rises rapidly, forcing short sellers to buy back shares and driving the price even higher', 'When you sell shares quickly', 'A small profit on a short trade', 'When the market closes early'], correctAnswer: 'When a heavily shorted stock rises rapidly, forcing short sellers to buy back shares and driving the price even higher', difficulty: 'medium', explanation: 'Short squeezes create a feedback loop: rising prices force short sellers to cover (buy back shares), which pushes the price even higher, forcing more shorts to cover. GameStop in 2021 was a famous example.' },
    { type: 'fill_gap', prompt: 'The "short interest ratio" or "days to cover" divides short interest by the stock\'s average daily ___.', options: ['volume', 'price', 'earnings', 'dividend'], correctAnswer: 'volume', difficulty: 'medium', explanation: 'Days to cover estimates how many days it would take all short sellers to buy back their shares based on average daily volume. A high ratio (5+ days) means short sellers would struggle to exit quickly if the stock rises.' },
    { type: 'true_false', prompt: 'Short sellers must pay any dividends issued on the shares they borrowed.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'When you short a stock, you owe the lender any dividends paid during the time you hold the short position. This is an additional cost that reduces short-selling profitability on dividend-paying stocks.' },
    { type: 'multiple_choice', prompt: 'What does "covering a short" mean?', options: ['Hiding a short position from others', 'Buying back the borrowed shares to close the short position', 'Adding more to a short position', 'Placing a stop-loss on a short'], correctAnswer: 'Buying back the borrowed shares to close the short position', difficulty: 'easy', explanation: 'To close (cover) a short position, you buy back the same number of shares you borrowed and return them to the lender. If you shorted at $50 and cover at $40, your profit is $10 per share minus fees.' },
    { type: 'multiple_choice', prompt: 'Why do regulators sometimes impose short-selling bans during market crises?', options: ['To prevent profits', 'Because short selling can accelerate price declines and increase panic during already fragile market conditions', 'Short selling is always illegal', 'To increase trading volume'], correctAnswer: 'Because short selling can accelerate price declines and increase panic during already fragile market conditions', difficulty: 'hard', explanation: 'During crises, aggressive short selling can create downward spirals of falling prices and forced liquidations. Temporary bans aim to stabilize markets, though their effectiveness is debated among economists.' },
    { type: 'true_false', prompt: 'You can short sell any stock at any time with no restrictions.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'hard', explanation: 'There are restrictions: some stocks are "hard to borrow" with limited shares available for lending, some brokers restrict short selling on certain securities, and regulations like the SEC\'s uptick rule can limit when shorts can be initiated.' },
  ];

  LESSON_QUESTIONS['Trading']['Pre-Market Trading'] = [
    { type: 'multiple_choice', prompt: 'What are pre-market trading hours in the US?', options: ['4:00 AM to 9:30 AM ET', '9:30 AM to 4:00 PM ET', '4:00 PM to 8:00 PM ET', '12:00 AM to 6:00 AM ET'], correctAnswer: '4:00 AM to 9:30 AM ET', difficulty: 'easy', explanation: 'Pre-market trading typically runs from 4:00 AM to 9:30 AM ET, before the regular session opens. Most retail brokers offer access starting at 7:00 AM ET.' },
    { type: 'true_false', prompt: 'Pre-market trading typically has lower volume and wider bid-ask spreads than regular hours.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'With fewer participants in pre-market, liquidity is thin. This leads to wider spreads between bid and ask prices, meaning you may pay more to buy or receive less when selling compared to regular hours.' },
    { type: 'multiple_choice', prompt: 'Why do traders monitor pre-market activity?', options: ['It has no significance', 'Pre-market price action can indicate how the regular session will open, reflecting overnight news and earnings reactions', 'Only to place limit orders', 'Pre-market prices are always accurate predictions'], correctAnswer: 'Pre-market price action can indicate how the regular session will open, reflecting overnight news and earnings reactions', difficulty: 'medium', explanation: 'Pre-market trading reflects reactions to overnight events, earnings reports, and global market moves. While it provides clues about opening direction, low volume means prices can shift significantly once regular trading begins.' },
    { type: 'fill_gap', prompt: 'After-hours trading occurs from 4:00 PM to ___ PM ET.', options: ['8:00', '6:00', '10:00', '5:00'], correctAnswer: '8:00', difficulty: 'easy', explanation: 'After-hours trading runs from 4:00 PM to 8:00 PM ET. Like pre-market, it features lower liquidity and wider spreads, but allows traders to react to earnings released after the market close.' },
    { type: 'true_false', prompt: 'Limit orders are recommended over market orders during pre-market and after-hours trading.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Due to low liquidity and wide spreads in extended hours, market orders can fill at unexpected prices. Limit orders let you set the maximum price you will pay or minimum price you will accept, protecting against poor fills.' },
    { type: 'multiple_choice', prompt: 'What type of orders are typically available during extended hours?', options: ['All order types including complex options strategies', 'Only limit orders at most brokerages', 'Only market orders', 'Stop-loss orders only'], correctAnswer: 'Only limit orders at most brokerages', difficulty: 'medium', explanation: 'Most brokers restrict extended-hours trading to limit orders only. This protects traders from the extreme price swings that can occur with low liquidity and prevents poor market order fills.' },
    { type: 'swipe_judge', prompt: 'Placing large market orders in pre-market with thin liquidity.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'medium', explanation: 'Large market orders in thin pre-market liquidity can move the price against you dramatically. You may end up buying at prices far above the current quote due to the lack of sellers at the displayed price.' },
    { type: 'true_false', prompt: 'A stock\'s pre-market price always matches its opening price at 9:30 AM.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'hard', explanation: 'The opening price is determined by the exchange\'s opening auction process, which matches accumulated orders. A flood of new orders at the open can push the price significantly above or below the pre-market level.' },
  ];

  LESSON_QUESTIONS['Trading']['Earnings Reports'] = [
    { type: 'multiple_choice', prompt: 'How often do public companies report earnings?', options: ['Monthly', 'Quarterly', 'Annually only', 'Weekly'], correctAnswer: 'Quarterly', difficulty: 'easy', explanation: 'Public US companies are required by the SEC to report earnings every quarter (10-Q filings), with a comprehensive annual report (10-K). Earnings season occurs four times a year.' },
    { type: 'true_false', prompt: 'Earnings per share (EPS) is one of the most closely watched metrics in an earnings report.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'EPS measures the profit allocated to each outstanding share of stock. Analysts set EPS estimates before earnings, and whether the company beats or misses these estimates often drives the stock price reaction.' },
    { type: 'multiple_choice', prompt: 'What does it mean when a company "beats estimates"?', options: ['They released earnings early', 'Their reported EPS or revenue exceeded what analysts had predicted', 'Their stock price went up', 'They changed their fiscal year'], correctAnswer: 'Their reported EPS or revenue exceeded what analysts had predicted', difficulty: 'easy', explanation: 'Beating estimates means the company performed better than Wall Street consensus expectations. However, the stock reaction also depends on forward guidance — beating estimates with weak guidance can still cause a selloff.' },
    { type: 'fill_gap', prompt: 'Forward ___ is management\'s projection of future financial performance, often more impactful than the current quarter\'s numbers.', options: ['guidance', 'momentum', 'analysis', 'volume'], correctAnswer: 'guidance', difficulty: 'medium', explanation: 'Forward guidance tells investors what to expect in coming quarters. A company can beat current estimates but still see its stock drop if it lowers future guidance, because stock prices are forward-looking.' },
    { type: 'true_false', prompt: 'A stock can drop even after reporting earnings that beat analyst expectations.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'This is common and confuses many beginners. "Buy the rumor, sell the news" — if the beat was already priced in, or if forward guidance disappoints, the stock can sell off despite strong current results.' },
    { type: 'multiple_choice', prompt: 'What is "earnings whisper"?', options: ['A secret company meeting', 'An unofficial, higher earnings estimate that reflects what traders actually expect, beyond the official analyst consensus', 'The sound the market makes', 'A low-volume trading day'], correctAnswer: 'An unofficial, higher earnings estimate that reflects what traders actually expect, beyond the official analyst consensus', difficulty: 'medium', explanation: 'The whisper number is the real expectation among traders. Companies often beat the official consensus but miss the whisper number, leading to disappointing stock reactions despite a technical "beat."' },
    { type: 'multiple_choice', prompt: 'What is implied volatility (IV) crush after earnings?', options: ['When the stock becomes more volatile', 'When option premiums collapse after earnings because the uncertain event has passed', 'When the company stops trading', 'When volume drops to zero'], correctAnswer: 'When option premiums collapse after earnings because the uncertain event has passed', difficulty: 'hard', explanation: 'Options are priced with extra premium before earnings to account for the potential big move. Once earnings are released, that uncertainty premium evaporates, causing option prices to drop even if the stock moves in your direction.' },
    { type: 'true_false', prompt: 'Revenue growth is often considered more important than EPS because earnings can be manipulated through accounting but revenue is harder to fabricate.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'hard', explanation: 'Revenue (top line) reflects actual demand for a company\'s products. EPS can be boosted by cost cuts, share buybacks, or accounting changes. Sustained revenue growth is a stronger indicator of a healthy, growing business.' },
  ];

  LESSON_QUESTIONS['Trading']['Tax & Trading'] = [
    { type: 'multiple_choice', prompt: 'What is the difference between short-term and long-term capital gains in the US?', options: ['There is no difference', 'Short-term gains (held under 1 year) are taxed at ordinary income rates, while long-term gains (held over 1 year) get lower tax rates', 'Long-term gains are taxed higher', 'Only short-term gains are taxed'], correctAnswer: 'Short-term gains (held under 1 year) are taxed at ordinary income rates, while long-term gains (held over 1 year) get lower tax rates', difficulty: 'easy', explanation: 'The US tax code rewards longer holding periods. Short-term gains can be taxed up to 37%, while long-term capital gains rates are 0%, 15%, or 20% depending on your income bracket.' },
    { type: 'true_false', prompt: 'Day traders typically owe short-term capital gains tax on their profits because they hold positions for less than a year.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Since day traders close positions within the same day, all profits are short-term capital gains taxed at ordinary income rates. This significantly higher tax rate is an important cost many new day traders overlook.' },
    { type: 'multiple_choice', prompt: 'What is the wash sale rule?', options: ['You must wash your hands before trading', 'You cannot deduct a loss if you buy the same or substantially identical security within 30 days before or after the sale', 'You must sell all stocks at year-end', 'A rule about cleaning up old orders'], correctAnswer: 'You cannot deduct a loss if you buy the same or substantially identical security within 30 days before or after the sale', difficulty: 'medium', explanation: 'The wash sale rule prevents traders from selling at a loss for the tax deduction and immediately buying back the same stock. The 30-day window applies both before and after the loss sale.' },
    { type: 'fill_gap', prompt: 'You can deduct up to $___  in net capital losses against ordinary income per year in the US.', options: ['3,000', '10,000', '1,000', '5,000'], correctAnswer: '3,000', difficulty: 'medium', explanation: 'If your capital losses exceed your gains, you can deduct up to $3,000 ($1,500 if married filing separately) against your ordinary income. Excess losses carry forward to future tax years indefinitely.' },
    { type: 'true_false', prompt: 'Tax-loss harvesting is a strategy where you sell losing positions to offset gains and reduce your tax bill.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Tax-loss harvesting involves strategically selling investments at a loss to offset capital gains from winning trades. It is a legitimate and widely used strategy to minimize annual tax liability.' },
    { type: 'multiple_choice', prompt: 'What is the tax advantage of trading inside a Roth IRA?', options: ['No advantage', 'Gains are tax-deferred', 'Qualified withdrawals including all gains are completely tax-free', 'Only dividends are tax-free'], correctAnswer: 'Qualified withdrawals including all gains are completely tax-free', difficulty: 'medium', explanation: 'Roth IRA contributions are made with after-tax money, but all growth and qualified withdrawals are tax-free. This makes it extremely powerful for long-term investing — decades of compounding with zero tax on gains.' },
    { type: 'multiple_choice', prompt: 'Which form does your broker send for reporting capital gains and losses?', options: ['W-2', '1099-B', '1099-INT', 'Schedule A'], correctAnswer: '1099-B', difficulty: 'hard', explanation: 'Form 1099-B reports proceeds from broker transactions including stocks, options, and other securities. It details each sale, cost basis, and whether the gain or loss is short-term or long-term.' },
    { type: 'true_false', prompt: 'Cryptocurrency trades are not subject to capital gains tax in the US.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'hard', explanation: 'The IRS treats cryptocurrency as property. Every sale, trade, or exchange of crypto is a taxable event subject to capital gains tax. Even swapping one crypto for another triggers a taxable event.' },
  ];

  LESSON_QUESTIONS['Trading']['Stochastic Oscillator'] = [
    { type: 'multiple_choice', prompt: 'What does the Stochastic Oscillator measure?', options: ['Trading volume over time', 'The closing price relative to the high-low range over a set period', 'The number of shares outstanding', 'Company revenue growth'], correctAnswer: 'The closing price relative to the high-low range over a set period', difficulty: 'easy', explanation: 'The Stochastic Oscillator compares a security\'s closing price to its price range over a specific period (usually 14 days), generating a value between 0 and 100.' },
    { type: 'true_false', prompt: 'A Stochastic reading above 80 is generally considered overbought.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Readings above 80 indicate the price is closing near the top of its range, suggesting overbought conditions. However, in strong uptrends, the oscillator can remain overbought for extended periods.' },
    { type: 'multiple_choice', prompt: 'What are the two lines on a Stochastic Oscillator called?', options: ['MACD and Signal', '%K and %D', 'Upper and Lower Band', 'Fast and Slow MA'], correctAnswer: '%K and %D', difficulty: 'easy', explanation: '%K is the fast line showing the current stochastic value, and %D is the slow line (a 3-period moving average of %K). Crossovers between these lines generate trading signals.' },
    { type: 'fill_gap', prompt: 'A Stochastic reading below ___ is generally considered oversold.', options: ['20', '50', '80', '10'], correctAnswer: '20', difficulty: 'easy', explanation: 'Readings below 20 indicate the price is closing near the bottom of its range, suggesting oversold conditions and a potential reversal to the upside.' },
    { type: 'multiple_choice', prompt: 'What is a bullish signal on the Stochastic Oscillator?', options: ['%K crossing above %D in the oversold zone', '%K crossing below %D in the overbought zone', 'Both lines at 50', 'The oscillator reaching exactly 100'], correctAnswer: '%K crossing above %D in the oversold zone', difficulty: 'medium', explanation: 'When %K crosses above %D while both are below 20 (oversold), it signals momentum is shifting upward and a price reversal may be beginning.' },
    { type: 'true_false', prompt: 'The Stochastic Oscillator works best as a standalone indicator without any confirmation.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'Like most oscillators, the Stochastic produces false signals, especially in trending markets. Combining it with support/resistance levels, trendlines, or other indicators significantly improves reliability.' },
    { type: 'multiple_choice', prompt: 'What is Stochastic divergence?', options: ['When the oscillator breaks above 100', 'When price makes a new low but the Stochastic makes a higher low', 'When %K and %D move in the same direction', 'When volume increases with price'], correctAnswer: 'When price makes a new low but the Stochastic makes a higher low', difficulty: 'hard', explanation: 'Bullish divergence occurs when price makes a lower low but the Stochastic makes a higher low, indicating weakening downward momentum and a potential reversal.' },
    { type: 'true_false', prompt: 'In a strong uptrend, the Stochastic Oscillator can remain above 80 for weeks without the price reversing.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'In strongly trending markets, overbought or oversold readings can persist for long periods. This is why selling purely because the Stochastic is above 80 can cause you to exit profitable trends too early.' },
  ];

  LESSON_QUESTIONS['Trading']['Average True Range'] = [
    { type: 'multiple_choice', prompt: 'What does the Average True Range (ATR) measure?', options: ['The direction of a trend', 'Market volatility over a given period', 'Trading volume', 'Price momentum'], correctAnswer: 'Market volatility over a given period', difficulty: 'easy', explanation: 'ATR measures market volatility by calculating the average of true ranges over a specified period (typically 14 days). It does not indicate direction, only how much price is moving.' },
    { type: 'true_false', prompt: 'A rising ATR indicates increasing market volatility.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'When ATR is rising, it means the average price range per period is expanding, indicating greater volatility. This often happens during breakouts or market sell-offs.' },
    { type: 'multiple_choice', prompt: 'How can traders use ATR for stop-loss placement?', options: ['Set the stop-loss at exactly 1 ATR below entry', 'ATR cannot be used for stop-losses', 'Multiply ATR by a factor (e.g., 2x ATR) below entry to set a volatility-adjusted stop', 'Place the stop at the ATR value itself'], correctAnswer: 'Multiply ATR by a factor (e.g., 2x ATR) below entry to set a volatility-adjusted stop', difficulty: 'medium', explanation: 'Using a multiple of ATR (commonly 1.5x to 3x) for stop-loss placement adapts your stop to current market conditions. In volatile markets, stops widen to avoid being stopped out by normal price noise.' },
    { type: 'fill_gap', prompt: 'The "true range" is the greatest of: current high minus low, absolute value of high minus previous ___, or absolute value of low minus previous close.', options: ['Close', 'Open', 'High', 'Volume'], correctAnswer: 'Close', difficulty: 'medium', explanation: 'True range accounts for gaps by comparing the current bar\'s range to the previous close. This captures overnight gaps that a simple high-minus-low calculation would miss.' },
    { type: 'true_false', prompt: 'ATR tells you which direction the price will move.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'ATR is a pure volatility measure and is directionless. A high ATR means large price swings but gives no indication of whether the price will go up or down.' },
    { type: 'multiple_choice', prompt: 'What does a low ATR value typically indicate?', options: ['A strong uptrend', 'A period of consolidation with low volatility', 'High trading volume', 'An imminent crash'], correctAnswer: 'A period of consolidation with low volatility', difficulty: 'easy', explanation: 'Low ATR values indicate the price is moving in a narrow range, often during consolidation phases. These low-volatility periods frequently precede significant breakout moves.' },
    { type: 'swipe_judge', prompt: 'Using a fixed dollar amount stop-loss regardless of how volatile the stock is.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'medium', explanation: 'A fixed dollar stop ignores volatility. A $2 stop on a stock with a $5 daily ATR will get triggered by normal noise. Use ATR-based stops that adapt to each asset\'s volatility.' },
    { type: 'multiple_choice', prompt: 'If a stock has an ATR of $3.50 and you want a 2x ATR stop, how far below your entry should the stop be?', options: ['$3.50', '$1.75', '$7.00', '$10.50'], correctAnswer: '$7.00', difficulty: 'hard', explanation: '$3.50 ATR multiplied by 2 equals $7.00. This gives the trade enough room to absorb normal volatility while still protecting against a genuine adverse move.' },
  ];

  LESSON_QUESTIONS['Trading']['VWAP Trading'] = [
    { type: 'multiple_choice', prompt: 'What does VWAP stand for?', options: ['Volume Weighted Average Price', 'Variable Width Analysis Pattern', 'Volatile Weekly Average Projection', 'Value Weighted Asset Portfolio'], correctAnswer: 'Volume Weighted Average Price', difficulty: 'easy', explanation: 'VWAP stands for Volume Weighted Average Price. It calculates the average price a security has traded at throughout the day, weighted by volume at each price level.' },
    { type: 'true_false', prompt: 'VWAP resets at the start of each new trading day.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'VWAP is an intraday indicator that resets every session. It accumulates volume and price data from the market open, making it most relevant for day traders.' },
    { type: 'multiple_choice', prompt: 'If a stock is trading above VWAP, what does this generally indicate?', options: ['The stock is overvalued', 'Buyers are in control and the intraday trend is bullish', 'The stock will crash', 'Volume is decreasing'], correctAnswer: 'Buyers are in control and the intraday trend is bullish', difficulty: 'easy', explanation: 'Price above VWAP suggests buyers are willing to pay above the average price, indicating bullish intraday sentiment. Many institutional traders use VWAP as a benchmark for execution quality.' },
    { type: 'true_false', prompt: 'Institutional traders frequently use VWAP to evaluate whether they got a good fill on large orders.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Institutions measure execution quality against VWAP. Buying below VWAP means they paid less than the average participant, while selling above VWAP means they sold at a premium.' },
    { type: 'fill_gap', prompt: 'VWAP is most useful for ___ traders because it resets daily.', options: ['Day', 'Swing', 'Position', 'Long-term'], correctAnswer: 'Day', difficulty: 'easy', explanation: 'Since VWAP resets at the open each day, it is primarily an intraday tool. Day traders use it to gauge trend direction, find entries, and set targets within a single session.' },
    { type: 'multiple_choice', prompt: 'What is a common VWAP trading strategy?', options: ['Buy when price is far above VWAP', 'Buy pullbacks to VWAP in an uptrend as it often acts as dynamic support', 'Sell whenever price touches VWAP', 'Ignore VWAP entirely'], correctAnswer: 'Buy pullbacks to VWAP in an uptrend as it often acts as dynamic support', difficulty: 'medium', explanation: 'In an uptrend, VWAP often acts as dynamic support. Traders buy when price pulls back to VWAP and bounces, entering at the average price with a favorable risk-reward.' },
    { type: 'swipe_judge', prompt: 'Using VWAP on a weekly chart to make swing trading decisions.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'medium', explanation: 'VWAP is designed as an intraday indicator that resets daily. Applying it to weekly or longer timeframes distorts its meaning and produces unreliable signals.' },
    { type: 'true_false', prompt: 'VWAP becomes less reliable in the first 15 minutes of trading because it has limited data.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'hard', explanation: 'Early in the session, VWAP is calculated from very few data points, making it erratic and unreliable. Most VWAP traders wait at least 15-30 minutes after the open before using it for decisions.' },
  ];

  LESSON_QUESTIONS['Trading']['Order Flow'] = [
    { type: 'multiple_choice', prompt: 'What is order flow in trading?', options: ['The speed of your internet connection', 'The analysis of buy and sell orders to understand supply and demand in real time', 'A type of moving average', 'The order in which stocks are listed on an exchange'], correctAnswer: 'The analysis of buy and sell orders to understand supply and demand in real time', difficulty: 'easy', explanation: 'Order flow analysis examines the actual buy and sell orders hitting the market to understand who is in control — buyers or sellers — and at what price levels significant interest exists.' },
    { type: 'true_false', prompt: 'The order book shows all pending limit orders at different price levels.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'The order book (also called Level 2 or market depth) displays all resting limit orders at each price level, showing where buyers and sellers are willing to transact.' },
    { type: 'multiple_choice', prompt: 'What does a large cluster of buy limit orders below the current price suggest?', options: ['Resistance above', 'A potential support level where buyers are waiting', 'The stock is about to crash', 'Low trading volume'], correctAnswer: 'A potential support level where buyers are waiting', difficulty: 'easy', explanation: 'Large buy orders stacked below the current price create a "wall" of demand that can act as support. Sellers pushing the price down may struggle to get through this cluster of buy orders.' },
    { type: 'fill_gap', prompt: 'A market order that hits the ___ side removes liquidity and is called an aggressive order.', options: ['Ask', 'Bid', 'Mid', 'Spread'], correctAnswer: 'Ask', difficulty: 'medium', explanation: 'When a buyer places a market order, it hits the ask (the lowest price a seller is offering), consuming liquidity. This aggressive buying can push prices higher if sell-side liquidity is thin.' },
    { type: 'true_false', prompt: 'Iceberg orders are large orders that are fully visible in the order book.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'Iceberg orders hide the majority of their size, showing only a small visible portion. Institutions use them to disguise large orders and avoid moving the market against their position.' },
    { type: 'multiple_choice', prompt: 'What is "tape reading" in the context of order flow?', options: ['Reading news headlines on a ticker tape', 'Analyzing the time and sales data to see actual executed trades in real time', 'A type of technical indicator', 'Reading financial reports'], correctAnswer: 'Analyzing the time and sales data to see actual executed trades in real time', difficulty: 'medium', explanation: 'Tape reading involves watching the time and sales feed (the "tape") to observe the speed, size, and direction of actual executions, giving insight into real-time buying and selling pressure.' },
    { type: 'multiple_choice', prompt: 'What does "absorption" mean in order flow analysis?', options: ['A stock being delisted', 'Large resting orders absorbing aggressive orders without the price moving', 'The market absorbing news', 'A company absorbing debt'], correctAnswer: 'Large resting orders absorbing aggressive orders without the price moving', difficulty: 'hard', explanation: 'Absorption occurs when large limit orders at a price level consume incoming market orders without allowing price to break through. It signals strong conviction at that level and often precedes a reversal.' },
    { type: 'true_false', prompt: 'Order flow analysis is more useful for short-term traders than long-term investors.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Order flow data reflects real-time microstructure and is most actionable for scalpers and day traders. Long-term investors rely more on fundamentals, as order flow noise averages out over time.' },
  ];

  LESSON_QUESTIONS['Trading']['Dark Pools'] = [
    { type: 'multiple_choice', prompt: 'What is a dark pool?', options: ['An illegal trading venue', 'A private exchange where large orders are executed away from public markets', 'A type of cryptocurrency', 'A pool of money for short selling'], correctAnswer: 'A private exchange where large orders are executed away from public markets', difficulty: 'easy', explanation: 'Dark pools are legitimate private trading venues where institutional investors can execute large block orders without displaying them on public exchanges, minimizing market impact.' },
    { type: 'true_false', prompt: 'Dark pools are illegal in the United States.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'Dark pools are legal and regulated by the SEC. They serve an important market function by allowing institutions to trade large blocks without causing significant price movement.' },
    { type: 'multiple_choice', prompt: 'Why do institutional investors prefer dark pools for large orders?', options: ['To avoid paying taxes', 'To get faster execution speeds', 'To avoid showing their hand and moving the market against their position', 'Because dark pools have lower commissions'], correctAnswer: 'To avoid showing their hand and moving the market against their position', difficulty: 'easy', explanation: 'If an institution places a 1-million-share buy order on a public exchange, other traders would front-run it, driving the price up. Dark pools hide this order to get a better average fill.' },
    { type: 'true_false', prompt: 'Dark pool trades are eventually reported to the public after execution.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'While dark pool orders are hidden before execution, completed trades must be reported to a consolidated tape, usually within seconds. The data becomes public, but the market impact is already minimized.' },
    { type: 'fill_gap', prompt: 'Dark pools account for approximately ___% of all US equity trading volume.', options: ['40', '5', '90', '1'], correctAnswer: '40', difficulty: 'medium', explanation: 'Dark pools handle roughly 35-45% of total US equity volume, making them a massive component of market structure that retail traders should be aware of.' },
    { type: 'multiple_choice', prompt: 'What is "dark pool printing" that traders watch for?', options: ['Printing physical stock certificates', 'Large dark pool trades appearing on the tape that may signal institutional interest', 'Printing charts from dark pools', 'A type of fraud'], correctAnswer: 'Large dark pool trades appearing on the tape that may signal institutional interest', difficulty: 'medium', explanation: 'When large block trades from dark pools hit the tape, savvy traders analyze them for clues about institutional buying or selling. Repeated large prints at a price level can signal accumulation or distribution.' },
    { type: 'swipe_judge', prompt: 'Assuming that all dark pool activity is insider trading or manipulation.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'Dark pools serve a legitimate market function. While abuses can occur, most dark pool activity is simply institutions managing execution quality for large orders. Assuming it is all manipulation is misinformed.' },
    { type: 'multiple_choice', prompt: 'What regulatory concern exists around dark pools?', options: ['They use too much electricity', 'They could reduce price transparency and create information asymmetry between institutional and retail traders', 'They are too profitable for brokers', 'They slow down trading'], correctAnswer: 'They could reduce price transparency and create information asymmetry between institutional and retail traders', difficulty: 'hard', explanation: 'Critics argue dark pools fragment liquidity and create a two-tiered market where institutions have access to better pricing and information, disadvantaging retail traders who only see public exchange data.' },
  ];

  LESSON_QUESTIONS['Trading']['Algorithmic Trading'] = [
    { type: 'multiple_choice', prompt: 'What is algorithmic trading?', options: ['Trading based on gut feelings', 'Using computer programs to execute trades automatically based on predefined rules', 'A type of fundamental analysis', 'Manual day trading with multiple screens'], correctAnswer: 'Using computer programs to execute trades automatically based on predefined rules', difficulty: 'easy', explanation: 'Algorithmic trading uses software to follow a defined set of rules (timing, price, volume, or mathematical models) to place trades, removing human emotion from the process.' },
    { type: 'true_false', prompt: 'High-frequency trading (HFT) is a subset of algorithmic trading that executes thousands of orders per second.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'HFT firms use powerful computers and co-located servers to execute massive numbers of orders in microseconds, profiting from tiny price discrepancies at scale.' },
    { type: 'multiple_choice', prompt: 'What is a major advantage of algorithmic trading over manual trading?', options: ['It guarantees profits', 'It removes emotional decision-making and executes consistently', 'It requires no initial setup', 'It works without a strategy'], correctAnswer: 'It removes emotional decision-making and executes consistently', difficulty: 'easy', explanation: 'Algorithms follow rules without fear, greed, or fatigue. They execute the same strategy consistently regardless of market conditions, eliminating the emotional mistakes that plague manual traders.' },
    { type: 'true_false', prompt: 'Algorithmic trading strategies never need to be updated or adjusted for changing market conditions.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'Markets evolve and strategies that worked in one regime can fail in another. Algorithms must be regularly monitored, backtested against recent data, and adjusted for changing volatility, correlations, and market structure.' },
    { type: 'fill_gap', prompt: 'A trading algorithm that profits from tiny price differences between two correlated assets is called ___ trading.', options: ['Arbitrage', 'Momentum', 'Reversal', 'Breakout'], correctAnswer: 'Arbitrage', difficulty: 'medium', explanation: 'Arbitrage strategies exploit price discrepancies between related instruments. Statistical arbitrage, pairs trading, and cross-exchange arbitrage are common algorithmic strategies.' },
    { type: 'multiple_choice', prompt: 'What is "slippage" in algorithmic trading?', options: ['A coding error', 'The difference between the expected execution price and the actual fill price', 'A type of trading fee', 'When the algorithm stops working'], correctAnswer: 'The difference between the expected execution price and the actual fill price', difficulty: 'medium', explanation: 'Slippage occurs when market conditions change between order submission and execution. It is a critical cost that must be factored into any algorithmic strategy to ensure backtested results match live performance.' },
    { type: 'swipe_judge', prompt: 'Deploying a trading algorithm with real money without first backtesting and paper trading it.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'Skipping backtesting and paper trading is reckless. Every algorithm must be rigorously tested on historical data and validated in a simulated environment before risking real capital.' },
    { type: 'multiple_choice', prompt: 'What is "overfitting" in the context of trading algorithms?', options: ['An algorithm that trades too frequently', 'When an algorithm is tuned so perfectly to historical data that it fails on new data', 'When a computer runs out of memory', 'An algorithm that makes too much profit'], correctAnswer: 'When an algorithm is tuned so perfectly to historical data that it fails on new data', difficulty: 'hard', explanation: 'Overfitting means the algorithm has learned the noise in historical data rather than genuine patterns. It shows amazing backtest results but performs poorly in live trading because it memorized the past instead of learning generalizable rules.' },
  ];

  LESSON_QUESTIONS['Trading']['Forex Basics'] = [
    { type: 'multiple_choice', prompt: 'What is the forex market?', options: ['A stock exchange in Europe', 'The global decentralized market for trading currencies', 'A commodity trading platform', 'A type of bond market'], correctAnswer: 'The global decentralized market for trading currencies', difficulty: 'easy', explanation: 'Forex (foreign exchange) is the world\'s largest financial market with over $7 trillion in daily volume. Currencies are traded in pairs (e.g., EUR/USD) across a global decentralized network.' },
    { type: 'true_false', prompt: 'The forex market operates 24 hours a day, five days a week.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Forex trades around the clock from Sunday evening to Friday evening (ET), following the sun across sessions: Sydney, Tokyo, London, and New York. This continuous operation creates unique trading opportunities.' },
    { type: 'multiple_choice', prompt: 'In the currency pair EUR/USD, what is the EUR called?', options: ['The quote currency', 'The counter currency', 'The base currency', 'The pip currency'], correctAnswer: 'The base currency', difficulty: 'easy', explanation: 'The first currency in a pair is the base currency (EUR), and the second is the quote currency (USD). EUR/USD = 1.10 means 1 euro costs 1.10 US dollars.' },
    { type: 'fill_gap', prompt: 'A ___ is the smallest price movement in a forex pair, typically the fourth decimal place.', options: ['Pip', 'Lot', 'Spread', 'Margin'], correctAnswer: 'Pip', difficulty: 'easy', explanation: 'A pip (percentage in point) is the smallest standard price move. For EUR/USD, one pip is 0.0001. For USD/JPY, one pip is 0.01 (second decimal) because of the yen\'s different value scale.' },
    { type: 'true_false', prompt: 'Forex brokers typically offer much higher leverage than stock brokers, sometimes 50:1 or even 100:1.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Forex brokers offer high leverage because currency moves are typically small in percentage terms. However, this magnifies both gains and losses, making risk management critical.' },
    { type: 'multiple_choice', prompt: 'What are the "major pairs" in forex?', options: ['Any pair with high volatility', 'Currency pairs that include the US dollar paired with other major economies', 'Pairs that only trade during US hours', 'The most expensive currencies'], correctAnswer: 'Currency pairs that include the US dollar paired with other major economies', difficulty: 'medium', explanation: 'Major pairs (EUR/USD, GBP/USD, USD/JPY, USD/CHF, AUD/USD, USD/CAD, NZD/USD) include the USD and account for the majority of forex volume, offering the tightest spreads and most liquidity.' },
    { type: 'multiple_choice', prompt: 'What factor has the biggest impact on currency exchange rates?', options: ['Stock market performance', 'Interest rate differentials between central banks', 'The weather', 'Social media trends'], correctAnswer: 'Interest rate differentials between central banks', difficulty: 'medium', explanation: 'Interest rates are the primary driver of currency values. Higher rates attract foreign capital seeking better returns, increasing demand for that currency. Central bank decisions move forex markets more than any other factor.' },
    { type: 'true_false', prompt: 'You can only profit in forex when a currency goes up in value.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'Forex is traded in pairs, so every trade involves buying one currency and selling another. You can profit from a currency falling by selling (shorting) the pair. Going short is just as common as going long in forex.' },
  ];

  LESSON_QUESTIONS['Trading']['Commodity Trading'] = [
    { type: 'multiple_choice', prompt: 'What is a commodity in trading?', options: ['Any stock listed on an exchange', 'A raw material or primary agricultural product that can be traded', 'A type of mutual fund', 'A government bond'], correctAnswer: 'A raw material or primary agricultural product that can be traded', difficulty: 'easy', explanation: 'Commodities are raw materials like gold, oil, wheat, and copper that are traded on specialized exchanges. They are standardized and interchangeable regardless of who produces them.' },
    { type: 'true_false', prompt: 'Gold is considered a "safe haven" commodity that often rises during economic uncertainty.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Gold has historically been viewed as a store of value during crises. When stocks fall or inflation rises, investors often flock to gold, driving its price up. This inverse correlation makes it a portfolio diversifier.' },
    { type: 'multiple_choice', prompt: 'What is the most commonly traded commodity in the world by volume?', options: ['Gold', 'Silver', 'Crude oil', 'Wheat'], correctAnswer: 'Crude oil', difficulty: 'easy', explanation: 'Crude oil (WTI and Brent) is the most heavily traded commodity globally due to its critical role in the global economy. Oil prices affect transportation, manufacturing, and overall economic activity.' },
    { type: 'multiple_choice', prompt: 'What is a futures contract in commodity trading?', options: ['A prediction about future prices', 'A legally binding agreement to buy or sell a commodity at a predetermined price on a future date', 'An option to trade later', 'A type of insurance'], correctAnswer: 'A legally binding agreement to buy or sell a commodity at a predetermined price on a future date', difficulty: 'medium', explanation: 'Futures contracts obligate the buyer and seller to transact at a set price on a specific date. They are used for both hedging (farmers locking in crop prices) and speculation.' },
    { type: 'fill_gap', prompt: 'Commodity prices are heavily influenced by the basic economic principle of supply and ___.', options: ['Demand', 'Return', 'Interest', 'Credit'], correctAnswer: 'Demand', difficulty: 'easy', explanation: 'Supply and demand fundamentally drive commodity prices. A drought reducing wheat supply or China increasing oil demand can cause dramatic price swings in commodity markets.' },
    { type: 'true_false', prompt: 'You need to physically store a commodity to trade commodity futures.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'Most commodity futures traders never take physical delivery. Speculators close their positions before the delivery date, and many modern instruments like ETFs and CFDs provide commodity exposure without physical ownership.' },
    { type: 'multiple_choice', prompt: 'What is "contango" in commodity futures?', options: ['When futures prices are lower than the spot price', 'When futures prices are higher than the spot price, reflecting storage costs and interest', 'A type of commodity exchange', 'When a commodity stops trading'], correctAnswer: 'When futures prices are higher than the spot price, reflecting storage costs and interest', difficulty: 'hard', explanation: 'Contango occurs when future delivery contracts trade at a premium to the current spot price, typically reflecting storage costs, insurance, and financing. It is the normal state for most physical commodities.' },
    { type: 'swipe_judge', prompt: 'Trading commodity futures with maximum leverage because you watched a YouTube video about oil prices.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'medium', explanation: 'Commodity futures are already leveraged instruments. Using maximum leverage on a commodity trade based on social media tips is extremely risky and can result in losses exceeding your initial investment.' },
  ];

  LESSON_QUESTIONS['Trading']['Bond Market'] = [
    { type: 'multiple_choice', prompt: 'What is a bond?', options: ['A share of ownership in a company', 'A loan made by an investor to a borrower, typically a corporation or government', 'A type of stock option', 'A savings account at a bank'], correctAnswer: 'A loan made by an investor to a borrower, typically a corporation or government', difficulty: 'easy', explanation: 'When you buy a bond, you are lending money to the issuer (government or corporation) in exchange for regular interest payments and the return of principal at maturity.' },
    { type: 'true_false', prompt: 'When interest rates rise, existing bond prices fall.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Bond prices and interest rates have an inverse relationship. When new bonds offer higher rates, existing bonds with lower rates become less attractive, causing their market price to drop.' },
    { type: 'multiple_choice', prompt: 'What is the "yield" of a bond?', options: ['The original purchase price', 'The annual interest income expressed as a percentage of the bond\'s price', 'The total amount of the bond', 'The maturity date'], correctAnswer: 'The annual interest income expressed as a percentage of the bond\'s price', difficulty: 'easy', explanation: 'Yield represents the effective annual return on a bond. As bond prices change in the market, the yield adjusts inversely — falling prices mean higher yields and vice versa.' },
    { type: 'true_false', prompt: 'US Treasury bonds are considered among the safest investments because they are backed by the full faith and credit of the US government.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'US Treasuries are considered the benchmark for "risk-free" assets because the US government has never defaulted on its debt. This safety comes with lower yields compared to riskier bonds.' },
    { type: 'fill_gap', prompt: 'A bond\'s ___ is the date when the principal (face value) is returned to the investor.', options: ['Maturity', 'Coupon', 'Yield', 'Spread'], correctAnswer: 'Maturity', difficulty: 'easy', explanation: 'Maturity is the date when the bond issuer repays the face value to the bondholder. Bonds can have maturities ranging from a few months (T-bills) to 30 years (long-term Treasuries).' },
    { type: 'multiple_choice', prompt: 'What is the "yield curve" and why do traders watch it?', options: ['A chart of stock yields', 'A graph showing bond yields across different maturities, used to predict economic conditions', 'A curve showing trading profits', 'A type of technical indicator'], correctAnswer: 'A graph showing bond yields across different maturities, used to predict economic conditions', difficulty: 'medium', explanation: 'The yield curve plots interest rates of bonds with different maturities. An inverted yield curve (short-term rates higher than long-term) has historically preceded recessions, making it a closely watched economic indicator.' },
    { type: 'multiple_choice', prompt: 'What is a "junk bond"?', options: ['A bond that has been canceled', 'A high-yield bond with a credit rating below investment grade (BB+ or lower)', 'A government bond', 'A bond with zero interest'], correctAnswer: 'A high-yield bond with a credit rating below investment grade (BB+ or lower)', difficulty: 'medium', explanation: 'Junk bonds (also called high-yield bonds) are issued by companies with lower credit ratings. They offer higher interest rates to compensate investors for the increased risk of default.' },
    { type: 'true_false', prompt: 'Bonds are generally less volatile than stocks, making them useful for portfolio diversification.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Bonds typically have lower price volatility than stocks and often move inversely to equities during market stress. This makes them valuable for reducing overall portfolio risk through diversification.' },
  ];

  LESSON_QUESTIONS['Trading']['IPO Trading'] = [
    { type: 'multiple_choice', prompt: 'What does IPO stand for?', options: ['Internal Price Offering', 'Initial Public Offering', 'Immediate Purchase Order', 'International Portfolio Option'], correctAnswer: 'Initial Public Offering', difficulty: 'easy', explanation: 'An IPO (Initial Public Offering) is the first time a private company offers its shares to the public on a stock exchange, allowing anyone to buy ownership in the company.' },
    { type: 'true_false', prompt: 'IPO stocks are generally considered low-risk investments suitable for beginners.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'IPOs are among the riskiest trades. Newly public companies have limited trading history, can be extremely volatile on their first days, and many underperform the broader market in their first year.' },
    { type: 'multiple_choice', prompt: 'What is the "lock-up period" after an IPO?', options: ['The time when no one can buy the stock', 'A period (typically 90-180 days) when company insiders cannot sell their shares', 'When the stock price is locked at the IPO price', 'A required holding period for all investors'], correctAnswer: 'A period (typically 90-180 days) when company insiders cannot sell their shares', difficulty: 'medium', explanation: 'The lock-up period prevents insiders from dumping shares immediately after the IPO. When the lock-up expires, a flood of insider selling can push the stock price down significantly.' },
    { type: 'true_false', prompt: 'Most retail investors get access to IPO shares at the offering price before the stock starts trading publicly.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'IPO shares at the offering price are typically allocated to institutional investors and high-net-worth clients of the underwriting banks. Retail investors usually buy at the market open price, which is often much higher.' },
    { type: 'fill_gap', prompt: 'The difference between the IPO offering price and the first trade price on the open market is called the IPO ___.', options: ['Pop', 'Spread', 'Yield', 'Float'], correctAnswer: 'Pop', difficulty: 'medium', explanation: 'The "IPO pop" refers to the initial price jump when a stock begins public trading. While exciting, it means retail investors buying at the open are paying a premium over the offering price.' },
    { type: 'multiple_choice', prompt: 'What is a SPAC?', options: ['A type of options contract', 'A Special Purpose Acquisition Company that raises funds through an IPO to acquire a private company', 'A regulatory body', 'A high-frequency trading strategy'], correctAnswer: 'A Special Purpose Acquisition Company that raises funds through an IPO to acquire a private company', difficulty: 'medium', explanation: 'SPACs are "blank check companies" that IPO with the sole purpose of merging with a private company, taking it public without a traditional IPO process. They became extremely popular in 2020-2021.' },
    { type: 'swipe_judge', prompt: 'Buying an IPO stock on day one based purely on media hype without reading the S-1 filing.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'The S-1 filing contains critical information about the company\'s financials, risks, and business model. Buying on hype alone often leads to buying at inflated prices before the inevitable pullback.' },
    { type: 'multiple_choice', prompt: 'What commonly happens to many IPO stocks in the first 6-12 months after going public?', options: ['They always double in price', 'They get delisted', 'Many underperform the broader market as initial excitement fades and lock-up periods expire', 'They always pay dividends'], correctAnswer: 'Many underperform the broader market as initial excitement fades and lock-up periods expire', difficulty: 'hard', explanation: 'Research shows that a majority of IPOs underperform the S&P 500 in their first year. The combination of fading hype, lock-up expiration selling, and overly optimistic initial valuations contribute to this pattern.' },
  ];

  LESSON_QUESTIONS['Trading']['Penny Stocks'] = [
    { type: 'multiple_choice', prompt: 'What is generally considered a penny stock?', options: ['Any stock under $100', 'A stock trading under $5 per share, often on OTC markets', 'A stock in the technology sector', 'Any stock on the NYSE'], correctAnswer: 'A stock trading under $5 per share, often on OTC markets', difficulty: 'easy', explanation: 'The SEC defines penny stocks as securities trading under $5 per share. Many trade on OTC (over-the-counter) markets like the OTC Bulletin Board rather than major exchanges, with less regulatory oversight.' },
    { type: 'true_false', prompt: 'Penny stocks typically have high liquidity and tight bid-ask spreads.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'Penny stocks usually suffer from low liquidity and wide bid-ask spreads. This means you may struggle to exit a position at your desired price, and the spread itself can eat a significant percentage of your investment.' },
    { type: 'multiple_choice', prompt: 'What is a "pump and dump" scheme in penny stocks?', options: ['A legitimate trading strategy', 'A workout routine for traders', 'Fraudsters artificially inflate a stock price with false hype, then sell their shares at the peak', 'A way for companies to raise capital'], correctAnswer: 'Fraudsters artificially inflate a stock price with false hype, then sell their shares at the peak', difficulty: 'easy', explanation: 'Pump and dump is illegal market manipulation. Promoters buy cheap shares, hype the stock through misleading claims, wait for the price to spike, then dump their shares, leaving other investors with losses.' },
    { type: 'true_false', prompt: 'Penny stocks are required to file the same detailed financial reports with the SEC as companies on major exchanges.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'Many penny stocks trade on OTC markets with significantly reduced reporting requirements compared to NYSE or NASDAQ-listed companies. This lack of transparency makes it harder to evaluate the company and easier for fraud to occur.' },
    { type: 'fill_gap', prompt: 'The acronym OTC stands for Over the ___, referring to stocks traded outside major exchanges.', options: ['Counter', 'Chart', 'Commission', 'Capital'], correctAnswer: 'Counter', difficulty: 'easy', explanation: 'OTC (Over the Counter) refers to the decentralized market where securities not listed on major exchanges are traded directly between parties through a dealer network.' },
    { type: 'multiple_choice', prompt: 'Why are penny stocks particularly dangerous for new traders?', options: ['They are boring', 'They have no risk', 'Low liquidity, lack of information, susceptibility to manipulation, and extreme volatility', 'They cost too much money'], correctAnswer: 'Low liquidity, lack of information, susceptibility to manipulation, and extreme volatility', difficulty: 'medium', explanation: 'Penny stocks combine multiple risk factors: thin liquidity makes exiting difficult, limited financial data makes analysis unreliable, they are prime targets for manipulation, and wild price swings can wipe out accounts quickly.' },
    { type: 'swipe_judge', prompt: 'Investing your entire savings into a penny stock because someone on social media said it will "go to the moon."', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'Social media penny stock tips are often pump and dump schemes. Investing your entire savings in any single stock — especially a volatile penny stock based on anonymous tips — is a recipe for financial disaster.' },
    { type: 'multiple_choice', prompt: 'What is "dilution" and why is it common with penny stocks?', options: ['When a stock becomes more valuable', 'When a company issues new shares, reducing existing shareholders\' ownership percentage', 'When trading volume increases', 'A type of technical indicator'], correctAnswer: 'When a company issues new shares, reducing existing shareholders\' ownership percentage', difficulty: 'hard', explanation: 'Many penny stock companies repeatedly issue new shares to raise cash, diluting existing shareholders. A stock can drop 90% not because the company lost value, but because the share count increased tenfold.' },
  ];

  LESSON_QUESTIONS['Trading']['Trading Journals'] = [
    { type: 'multiple_choice', prompt: 'What is the primary purpose of a trading journal?', options: ['To impress other traders', 'To track trades, analyze performance, identify patterns in your behavior, and improve over time', 'To calculate taxes', 'To replace a trading plan'], correctAnswer: 'To track trades, analyze performance, identify patterns in your behavior, and improve over time', difficulty: 'easy', explanation: 'A trading journal is a systematic record of every trade and the reasoning behind it. By reviewing patterns in your wins and losses, you identify strengths to leverage and weaknesses to fix.' },
    { type: 'true_false', prompt: 'Professional traders consider journaling one of the most important habits for long-term success.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Almost every consistently profitable trader emphasizes journaling. It transforms trading from gambling into a data-driven business by creating a feedback loop for continuous improvement.' },
    { type: 'multiple_choice', prompt: 'Which of these should be recorded in a trading journal?', options: ['Only winning trades', 'Only losing trades', 'Every trade including entry/exit, position size, reasoning, emotions, and outcome', 'Only trades above $1,000'], correctAnswer: 'Every trade including entry/exit, position size, reasoning, emotions, and outcome', difficulty: 'easy', explanation: 'A complete journal logs every trade — winners and losers. Include your entry/exit prices, position size, the setup that triggered the trade, your emotional state, and post-trade analysis.' },
    { type: 'fill_gap', prompt: 'Recording your ___ state during trades helps you identify emotional patterns that lead to poor decisions.', options: ['Emotional', 'Financial', 'Physical', 'Social'], correctAnswer: 'Emotional', difficulty: 'easy', explanation: 'Tracking emotions like fear, greed, excitement, or revenge reveals behavioral patterns. You might discover that you consistently overtrade when angry or cut winners short when anxious.' },
    { type: 'true_false', prompt: 'You should only review your trading journal once a year.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'Regular journal reviews (weekly and monthly) are essential. Weekly reviews catch bad habits early, while monthly reviews reveal longer-term patterns in your strategy\'s performance and your decision-making.' },
    { type: 'multiple_choice', prompt: 'What metric should you track to measure your trading edge?', options: ['Total account balance only', 'Win rate combined with average win size versus average loss size (expectancy)', 'Number of trades per day', 'Time spent watching charts'], correctAnswer: 'Win rate combined with average win size versus average loss size (expectancy)', difficulty: 'medium', explanation: 'Expectancy = (Win Rate x Avg Win) - (Loss Rate x Avg Loss). A 40% win rate can be very profitable if winners are 3x larger than losers. Your journal reveals whether you have a genuine statistical edge.' },
    { type: 'before_after', prompt: 'Which approach to tracking trades is better?', options: ['I lost money today. Oh well, tomorrow is a new day.', 'I lost $200 on AAPL. Entry was late, I chased. Lesson: wait for pullback to VWAP.'], correctAnswer: 'I lost $200 on AAPL. Entry was late, I chased. Lesson: wait for pullback to VWAP.', difficulty: 'medium', explanation: 'Specific, actionable journal entries create learning opportunities. Vague entries provide no insight. Detail the ticker, what went wrong, why, and what you will do differently next time.' },
    { type: 'multiple_choice', prompt: 'What is "revenge trading" and how does a journal help prevent it?', options: ['Trading stocks of competitors', 'Making impulsive trades to recover losses, which a journal can flag by showing emotional patterns', 'A profitable strategy', 'Trading during market revenge'], correctAnswer: 'Making impulsive trades to recover losses, which a journal can flag by showing emotional patterns', difficulty: 'hard', explanation: 'Revenge trading is impulsively entering trades to "win back" losses. A journal with emotion tracking reveals this pattern — you might notice your worst losses always follow a losing trade. Recognizing the pattern is the first step to breaking it.' },
  ];

  LESSON_QUESTIONS['Trading']['Risk Management Advanced'] = [
    { type: 'multiple_choice', prompt: 'What is the "Kelly Criterion" used for in trading?', options: ['Choosing which stocks to buy', 'Calculating the optimal position size based on your win rate and reward-to-risk ratio', 'Timing market entries', 'Selecting a broker'], correctAnswer: 'Calculating the optimal position size based on your win rate and reward-to-risk ratio', difficulty: 'medium', explanation: 'The Kelly Criterion is a mathematical formula that determines the ideal percentage of your capital to risk on each trade, maximizing long-term growth while minimizing ruin. Most traders use a fraction (quarter or half Kelly) for safety.' },
    { type: 'true_false', prompt: 'Correlation risk means that holding multiple positions in the same sector can amplify losses if that sector drops.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'If you hold five tech stocks, a sector-wide sell-off hits all positions simultaneously. True diversification means spreading risk across uncorrelated assets so a single event cannot damage your entire portfolio.' },
    { type: 'multiple_choice', prompt: 'What is "maximum drawdown" and why is it important?', options: ['The maximum amount you can withdraw', 'The largest peak-to-trough decline in your account, measuring your worst-case loss', 'The highest amount of profit', 'The maximum number of trades per day'], correctAnswer: 'The largest peak-to-trough decline in your account, measuring your worst-case loss', difficulty: 'medium', explanation: 'Maximum drawdown is the deepest your account has fallen from a peak. A 50% drawdown requires a 100% return to recover. Knowing your max drawdown helps you assess whether you can psychologically and financially survive your strategy\'s worst period.' },
    { type: 'fill_gap', prompt: 'A portfolio with a 50% drawdown requires a ___% gain just to break even.', options: ['100', '50', '75', '25'], correctAnswer: '100', difficulty: 'medium', explanation: 'If $10,000 drops 50% to $5,000, you need a 100% gain ($5,000) to return to $10,000. This asymmetry is why preserving capital and limiting drawdowns is more important than maximizing gains.' },
    { type: 'true_false', prompt: 'Risking 10% of your account per trade is considered conservative risk management.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'Risking 10% per trade is extremely aggressive. Five consecutive losses would cut your account in half. Professional traders typically risk 0.5% to 2% per trade to survive inevitable losing streaks.' },
    { type: 'multiple_choice', prompt: 'What is "risk of ruin" in trading?', options: ['The risk of a company going bankrupt', 'The probability of losing your entire trading account based on your position sizing and win rate', 'The risk of a market crash', 'The cost of trading commissions'], correctAnswer: 'The probability of losing your entire trading account based on your position sizing and win rate', difficulty: 'hard', explanation: 'Risk of ruin calculates the statistical likelihood of blowing up your account given your win rate, risk per trade, and reward ratio. Even profitable strategies can have high ruin probability if position sizes are too large.' },
    { type: 'multiple_choice', prompt: 'What is the purpose of a "circuit breaker" in risk management?', options: ['Fixing electrical problems', 'A pre-set rule to stop trading after a certain daily loss, preventing emotional spiraling', 'A type of trading order', 'An exchange regulation only'], correctAnswer: 'A pre-set rule to stop trading after a certain daily loss, preventing emotional spiraling', difficulty: 'easy', explanation: 'Personal circuit breakers (e.g., stop trading after losing 3% in a day) prevent emotional decision-making. After consecutive losses, your judgment deteriorates. Walking away preserves capital for the next session.' },
    { type: 'swipe_judge', prompt: 'Removing your stop-loss because you are convinced the stock will bounce back.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'Moving or removing stop-losses is one of the most destructive habits in trading. Your stop was set when you were rational. Removing it in the heat of the moment turns a small planned loss into a potentially catastrophic one.' },
  ];

  LESSON_QUESTIONS['Trading']['Tape Reading'] = [
    { type: 'multiple_choice', prompt: 'What is "the tape" in trading?', options: ['Adhesive tape for charts', 'The real-time stream of executed trades showing price, volume, and time', 'A news ticker', 'A type of chart pattern'], correctAnswer: 'The real-time stream of executed trades showing price, volume, and time', difficulty: 'easy', explanation: 'The tape (time and sales) displays every executed trade in real time. Originally a physical ticker tape machine, today it is a digital feed that shows the price, size, and timestamp of each transaction.' },
    { type: 'true_false', prompt: 'Tape reading was one of the earliest forms of technical analysis, used by legendary traders like Jesse Livermore.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Jesse Livermore, one of the greatest traders in history, made his fortune reading the ticker tape in the early 1900s. The principles of tape reading — tracking price and volume flow — remain relevant in modern electronic markets.' },
    { type: 'multiple_choice', prompt: 'What does a rapid succession of large buy orders on the tape indicate?', options: ['The stock is about to be delisted', 'Aggressive buying pressure, potentially from institutional investors', 'The market is about to close', 'Low volatility ahead'], correctAnswer: 'Aggressive buying pressure, potentially from institutional investors', difficulty: 'easy', explanation: 'Large consecutive buy orders hitting the ask suggest urgent, aggressive buying — often from institutions building a position. This buying pressure can push prices higher, especially if sell-side liquidity is thin.' },
    { type: 'fill_gap', prompt: 'A trade executed at the ___ price indicates the buyer was aggressive and paid the seller\'s asking price.', options: ['Ask', 'Bid', 'Mid', 'Open'], correctAnswer: 'Ask', difficulty: 'medium', explanation: 'Trades at the ask price mean buyers are "lifting the offer" — they are paying the seller\'s price rather than waiting. This aggressive buying is a sign of demand and bullish pressure.' },
    { type: 'true_false', prompt: 'Small, frequent trades on the tape are more significant than occasional large block trades.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'Large block trades carry more weight because they represent significant capital commitment. While small trades can show retail sentiment, large institutional blocks on the tape often signal where the "smart money" is positioned.' },
    { type: 'multiple_choice', prompt: 'What is "speed of tape" and why does it matter?', options: ['How fast your internet loads data', 'The rate at which trades are printing, indicating urgency and momentum', 'The speed of high-frequency trading', 'How quickly news is released'], correctAnswer: 'The rate at which trades are printing, indicating urgency and momentum', difficulty: 'medium', explanation: 'When the tape speeds up (trades print rapidly), it indicates heightened activity and urgency. Fast tape at a key level can signal a breakout or breakdown is imminent as participants rush to act.' },
    { type: 'multiple_choice', prompt: 'What does it mean when you see many trades printing at the bid price?', options: ['Buyers are in control', 'Sellers are aggressively dumping shares at the buyer\'s lower price', 'The spread is narrowing', 'The market is about to open'], correctAnswer: 'Sellers are aggressively dumping shares at the buyer\'s lower price', difficulty: 'hard', explanation: 'Trades at the bid mean sellers are hitting the bid — they are willing to accept the buyer\'s lower price to get out quickly. Heavy selling at the bid signals bearish pressure and urgency to exit.' },
    { type: 'swipe_judge', prompt: 'Making trading decisions based solely on tape reading without any other confluence factors.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'medium', explanation: 'Tape reading is most powerful when combined with other analysis — support/resistance levels, chart patterns, and overall market context. Using it in isolation can lead to misinterpreting normal market noise as significant signals.' },
  ];

  LESSON_QUESTIONS['Trading']['Options Greeks'] = [
    { type: 'multiple_choice', prompt: 'What does "Delta" measure in options trading?', options: ['Time decay per day', 'How much the option price changes for a $1 move in the underlying stock', 'The volatility of the option', 'The interest rate sensitivity'], correctAnswer: 'How much the option price changes for a $1 move in the underlying stock', difficulty: 'easy', explanation: 'Delta ranges from 0 to 1 for calls and 0 to -1 for puts. A delta of 0.50 means the option gains $0.50 for every $1 the stock moves in the favorable direction.' },
    { type: 'true_false', prompt: 'Theta represents time decay and works against option buyers as expiration approaches.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Theta measures how much an option loses in value each day due to the passage of time. Option buyers lose theta daily, while option sellers benefit from it. Time decay accelerates as expiration approaches.' },
    { type: 'multiple_choice', prompt: 'What does "Vega" measure?', options: ['The speed of price changes', 'The option\'s sensitivity to changes in implied volatility', 'The number of contracts traded', 'The distance to the strike price'], correctAnswer: 'The option\'s sensitivity to changes in implied volatility', difficulty: 'medium', explanation: 'Vega tells you how much the option price changes for a 1% change in implied volatility. High vega means the option is very sensitive to volatility changes, making it important during earnings or events.' },
    { type: 'true_false', prompt: 'Gamma is highest for at-the-money options near expiration.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Gamma measures the rate of change of delta. At-the-money options near expiration have the highest gamma because small stock price changes can rapidly shift the option from worthless to valuable (or vice versa).' },
    { type: 'fill_gap', prompt: 'The Greek letter ___ measures how much an option\'s delta changes when the stock moves $1.', options: ['Gamma', 'Theta', 'Rho', 'Vega'], correctAnswer: 'Gamma', difficulty: 'easy', explanation: 'Gamma is the rate of change of delta. High gamma means delta shifts rapidly with stock movement, creating both opportunity and risk. Gamma is critical for understanding how your position\'s risk profile changes.' },
    { type: 'multiple_choice', prompt: 'Why is selling options sometimes called "picking up pennies in front of a steamroller"?', options: ['Because options are cheap', 'Because option sellers collect small premiums (theta) but face potentially unlimited risk from large sudden moves', 'Because it requires fast execution', 'Because you can only make pennies'], correctAnswer: 'Because option sellers collect small premiums (theta) but face potentially unlimited risk from large sudden moves', difficulty: 'hard', explanation: 'Option sellers profit from time decay, collecting small consistent premiums. But a sudden large move (a "black swan") can produce losses many times larger than all premiums collected, like a steamroller crushing everything in its path.' },
    { type: 'multiple_choice', prompt: 'What does "Rho" measure in options?', options: ['The option\'s sensitivity to changes in interest rates', 'The rate of time decay', 'The volatility of the underlying', 'The delta of the delta'], correctAnswer: 'The option\'s sensitivity to changes in interest rates', difficulty: 'medium', explanation: 'Rho measures how an option\'s price changes with a 1% change in interest rates. It is typically the least significant Greek for short-term traders but matters more for long-dated options (LEAPS).' },
    { type: 'before_after', prompt: 'Which approach to options risk is better?', options: ['I sold 10 naked calls because I want the premium income.', 'I sold 10 covered calls against shares I already own to generate income with defined risk.'], correctAnswer: 'I sold 10 covered calls against shares I already own to generate income with defined risk.', difficulty: 'hard', explanation: 'Naked calls have unlimited risk — the stock can rise indefinitely. Covered calls (selling calls against shares you own) define your risk because you can deliver the shares if called. Always understand your maximum possible loss before entering an options trade.' },
  ];

  LESSON_QUESTIONS['Trading']['Ichimoku Cloud'] = [
    { type: 'multiple_choice', prompt: 'What is the Ichimoku Cloud (Kumo)?', options: ['A weather forecasting tool', 'A single moving average line', 'A comprehensive indicator showing support, resistance, trend, and momentum at a glance', 'A candlestick pattern'], correctAnswer: 'A comprehensive indicator showing support, resistance, trend, and momentum at a glance', difficulty: 'easy', explanation: 'The Ichimoku Cloud is a complete trading system developed by Goichi Hosoda. It displays support/resistance zones, trend direction, and momentum signals all in one overlay on the price chart.' },
    { type: 'true_false', prompt: 'When price is above the Ichimoku Cloud, it generally indicates a bullish trend.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Price above the cloud signals bullish momentum, price below signals bearish momentum, and price inside the cloud indicates a consolidation or transition phase.' },
    { type: 'multiple_choice', prompt: 'How many lines make up the full Ichimoku indicator?', options: ['2', '3', '5', '7'], correctAnswer: '5', difficulty: 'medium', explanation: 'The Ichimoku system has five lines: Tenkan-sen (conversion), Kijun-sen (base), Senkou Span A, Senkou Span B (which form the cloud), and Chikou Span (lagging span).' },
    { type: 'fill_gap', prompt: 'The ___ is the space between Senkou Span A and Senkou Span B on the Ichimoku chart.', options: ['Kumo', 'Kijun', 'Tenkan', 'Chikou'], correctAnswer: 'Kumo', difficulty: 'easy', explanation: 'Kumo means "cloud" in Japanese. It is the shaded area between Senkou Span A and Senkou Span B and acts as dynamic support and resistance.' },
    { type: 'true_false', prompt: 'A "Kumo twist" occurs when Senkou Span A crosses Senkou Span B, signaling a potential trend change.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'A Kumo twist is when the two cloud boundaries cross each other. A bullish twist occurs when Span A moves above Span B, and a bearish twist when Span A drops below Span B.' },
    { type: 'multiple_choice', prompt: 'What is the Chikou Span (Lagging Span)?', options: ['A future price projection', 'The current closing price plotted 26 periods back', 'An average of all five lines', 'The highest high of the last 52 periods'], correctAnswer: 'The current closing price plotted 26 periods back', difficulty: 'medium', explanation: 'The Chikou Span plots the current close 26 periods into the past. If it is above the price from 26 periods ago, it confirms bullish momentum.' },
    { type: 'multiple_choice', prompt: 'What does a "TK cross" refer to in Ichimoku analysis?', options: ['A candlestick pattern', 'The Tenkan-sen crossing the Kijun-sen, similar to a moving average crossover', 'Two cloud boundaries overlapping', 'A volume spike signal'], correctAnswer: 'The Tenkan-sen crossing the Kijun-sen, similar to a moving average crossover', difficulty: 'easy', explanation: 'The TK cross is when the faster Tenkan-sen crosses the slower Kijun-sen. A bullish TK cross above the cloud is a strong buy signal; a bearish TK cross below the cloud is a strong sell signal.' },
    { type: 'swipe_judge', prompt: 'Taking an Ichimoku buy signal when price is still deep inside the cloud.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'medium', explanation: 'The cloud represents indecision. Signals taken while price is inside the cloud are lower probability. Wait for price to break clearly above or below the cloud for stronger confirmation.' },
  ];

  LESSON_QUESTIONS['Trading']['Elliott Wave'] = [
    { type: 'multiple_choice', prompt: 'How many waves make up a complete Elliott Wave cycle?', options: ['3', '5', '8', '13'], correctAnswer: '8', difficulty: 'easy', explanation: 'A full Elliott Wave cycle has 8 waves: 5 impulse waves (1-2-3-4-5) in the direction of the trend, followed by 3 corrective waves (A-B-C) against the trend.' },
    { type: 'true_false', prompt: 'In Elliott Wave Theory, Wave 3 is typically the longest and strongest impulse wave.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Wave 3 is usually the longest and most powerful wave, driven by broad market participation. A key rule is that Wave 3 can never be the shortest of the three impulse waves (1, 3, and 5).' },
    { type: 'multiple_choice', prompt: 'What are the corrective waves in Elliott Wave Theory labeled?', options: ['X, Y, Z', '1, 2, 3', 'A, B, C', 'I, II, III'], correctAnswer: 'A, B, C', difficulty: 'easy', explanation: 'Corrective waves are labeled A, B, and C. Wave A moves against the trend, Wave B partially retraces A, and Wave C completes the correction, often reaching or exceeding the end of Wave A.' },
    { type: 'true_false', prompt: 'Wave 2 can retrace more than 100% of Wave 1 in Elliott Wave Theory.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'One of the inviolable rules of Elliott Wave is that Wave 2 never retraces more than 100% of Wave 1. If it does, the wave count is wrong and must be revised.' },
    { type: 'fill_gap', prompt: 'Elliott Wave Theory is closely linked to ___ ratios for projecting wave targets and retracements.', options: ['Fibonacci', 'Geometric', 'Arithmetic', 'Logarithmic'], correctAnswer: 'Fibonacci', difficulty: 'easy', explanation: 'Fibonacci ratios (0.382, 0.618, 1.618, etc.) are fundamental to Elliott Wave analysis. Wave 2 often retraces 61.8% of Wave 1, and Wave 3 often extends to 161.8% of Wave 1.' },
    { type: 'multiple_choice', prompt: 'What does "fractal nature" mean in the context of Elliott Waves?', options: ['Waves only appear on daily charts', 'Each wave contains smaller sub-waves of the same pattern, repeating at every scale', 'The pattern breaks apart randomly', 'Waves can only be counted on weekly timeframes'], correctAnswer: 'Each wave contains smaller sub-waves of the same pattern, repeating at every scale', difficulty: 'medium', explanation: 'Elliott Waves are fractal: each impulse wave subdivides into 5 smaller waves, and each corrective wave subdivides into 3 smaller waves. This self-similar pattern exists from 1-minute charts to multi-decade charts.' },
    { type: 'multiple_choice', prompt: 'Which wave is known as the "trap" wave that fools traders into thinking the trend has reversed?', options: ['Wave 1', 'Wave 4', 'Wave B', 'Wave 5'], correctAnswer: 'Wave B', difficulty: 'hard', explanation: 'Wave B is notorious for trapping traders. It moves in the direction of the prior trend, giving the false impression that the trend has resumed. Traders enter, only to get caught by the sharp Wave C move against them.' },
    { type: 'swipe_judge', prompt: 'Using Elliott Wave as your sole analysis method without any confirming indicators.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'Elliott Wave counting is subjective and prone to multiple valid interpretations. Combine it with volume analysis, RSI, moving averages, or Fibonacci levels to increase confidence in your wave count.' },
  ];

  LESSON_QUESTIONS['Trading']['Wyckoff Method'] = [
    { type: 'multiple_choice', prompt: 'What is the core principle of the Wyckoff Method?', options: ['Follow news headlines blindly', 'Markets move randomly', 'Price and volume reveal the intentions of large institutional operators (smart money)', 'Technical indicators are more reliable than price'], correctAnswer: 'Price and volume reveal the intentions of large institutional operators (smart money)', difficulty: 'easy', explanation: 'Richard Wyckoff developed his method in the early 1900s based on the idea that smart money (institutions) leave footprints in price and volume that observant traders can follow.' },
    { type: 'true_false', prompt: 'In the Wyckoff cycle, accumulation occurs when smart money quietly buys at low prices before a markup phase.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Accumulation is when institutions build positions at low prices in a trading range. The public is often bearish and selling during this phase. Once accumulation is complete, price enters the markup (uptrend) phase.' },
    { type: 'multiple_choice', prompt: 'What are the four phases of the Wyckoff market cycle in order?', options: ['Markup, Distribution, Accumulation, Markdown', 'Accumulation, Markup, Distribution, Markdown', 'Distribution, Markdown, Markup, Accumulation', 'Markdown, Accumulation, Distribution, Markup'], correctAnswer: 'Accumulation, Markup, Distribution, Markdown', difficulty: 'medium', explanation: 'The Wyckoff cycle follows: Accumulation (smart money buys low), Markup (prices rise), Distribution (smart money sells high), Markdown (prices fall). Then the cycle repeats.' },
    { type: 'fill_gap', prompt: 'A Wyckoff "spring" is a false ___ below a trading range designed to shake out weak holders.', options: ['Breakout', 'Rally', 'Gap', 'Candle'], correctAnswer: 'Breakout', difficulty: 'medium', explanation: 'A spring is a brief dip below support that triggers stop-losses and scares retail traders into selling. Smart money buys these shares cheaply before price reverses sharply upward.' },
    { type: 'true_false', prompt: 'In Wyckoff analysis, high volume on a price decline during a trading range is always bearish.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'High volume on a decline within a range can actually be bullish — it may indicate "selling climax" where the last sellers are exhausted and institutions are absorbing supply. Context matters more than volume alone.' },
    { type: 'multiple_choice', prompt: 'What is "the Composite Man" in Wyckoff Theory?', options: ['An AI trading bot', 'A hypothetical single entity representing all large institutional participants acting together', 'The CEO of the NYSE', 'A market index'], correctAnswer: 'A hypothetical single entity representing all large institutional participants acting together', difficulty: 'easy', explanation: 'Wyckoff suggested traders imagine a single "Composite Man" behind all market moves. This mental model helps understand how institutions accumulate, mark up, distribute, and mark down assets.' },
    { type: 'multiple_choice', prompt: 'What is an "upthrust" in Wyckoff analysis?', options: ['A gap up at market open', 'A false breakout above resistance in a distribution range, trapping buyers', 'A strong bullish candle', 'A type of order'], correctAnswer: 'A false breakout above resistance in a distribution range, trapping buyers', difficulty: 'hard', explanation: 'An upthrust is the mirror of a spring. Price briefly breaks above resistance, luring in breakout buyers, then reverses sharply. Smart money uses this to sell at higher prices to eager latecomers.' },
    { type: 'before_after', prompt: 'Which interpretation of a sell-off is better?', options: ['The stock dropped on huge volume — everyone is selling, I should too!', 'The stock dropped on huge volume near support — this could be a selling climax where institutions are absorbing supply.'], correctAnswer: 'The stock dropped on huge volume near support — this could be a selling climax where institutions are absorbing supply.', difficulty: 'hard', explanation: 'A Wyckoff approach looks at context: high-volume sell-offs at support can mark a selling climax, the point where selling is exhausted and institutions absorb the remaining supply before a reversal.' },
  ];

  LESSON_QUESTIONS['Trading']['Market Makers'] = [
    { type: 'multiple_choice', prompt: 'What is the primary role of a market maker?', options: ['To manipulate stock prices', 'To provide liquidity by continuously quoting bid and ask prices', 'To regulate the stock market', 'To give trading advice'], correctAnswer: 'To provide liquidity by continuously quoting bid and ask prices', difficulty: 'easy', explanation: 'Market makers ensure there is always a buyer and seller available by continuously posting bid (buy) and ask (sell) prices. They profit from the spread between these prices.' },
    { type: 'true_false', prompt: 'Market makers profit from the bid-ask spread.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Market makers buy at the bid price and sell at the ask price. The difference (the spread) is their compensation for providing liquidity and taking on inventory risk.' },
    { type: 'multiple_choice', prompt: 'What happens to bid-ask spreads during high volatility?', options: ['They narrow significantly', 'They remain unchanged', 'They widen to compensate market makers for increased risk', 'They disappear completely'], correctAnswer: 'They widen to compensate market makers for increased risk', difficulty: 'medium', explanation: 'During high volatility, market makers face greater risk of adverse price moves while holding inventory. They widen spreads to compensate, which increases trading costs for everyone.' },
    { type: 'true_false', prompt: 'Market makers are required to maintain orderly markets even during extreme volatility.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Designated market makers have obligations to maintain fair and orderly markets. On the NYSE, DMMs must provide liquidity and step in during imbalances, though they can widen spreads during stress.' },
    { type: 'fill_gap', prompt: 'The difference between the bid and ask price is called the ___.', options: ['Spread', 'Margin', 'Premium', 'Gap'], correctAnswer: 'Spread', difficulty: 'easy', explanation: 'The bid-ask spread is the cost of immediacy. Tighter spreads mean lower transaction costs and generally indicate a more liquid market.' },
    { type: 'multiple_choice', prompt: 'Why do large-cap stocks like Apple typically have tighter spreads than small-cap stocks?', options: ['Apple is more expensive', 'Higher liquidity and more market makers competing for order flow', 'The SEC regulates Apple differently', 'Small-cap stocks are more profitable'], correctAnswer: 'Higher liquidity and more market makers competing for order flow', difficulty: 'medium', explanation: 'Large-cap stocks attract many market makers competing for order flow, which narrows spreads. Small-cap stocks have fewer participants, less volume, and wider spreads as a result.' },
    { type: 'multiple_choice', prompt: 'What is "payment for order flow" (PFOF)?', options: ['Paying a fee to place a trade', 'A market maker paying a broker for the right to execute retail customer orders', 'A dividend payment', 'A regulatory fine'], correctAnswer: 'A market maker paying a broker for the right to execute retail customer orders', difficulty: 'hard', explanation: 'PFOF is when market makers like Citadel Securities pay brokers like Robinhood to route retail orders to them. The market maker profits by capturing the spread, while the broker offers commission-free trading.' },
    { type: 'swipe_judge', prompt: 'Placing market orders on low-volume stocks with wide bid-ask spreads.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'Market orders on illiquid stocks can fill at terrible prices far from the quoted price. Always use limit orders on low-volume stocks to control your entry and exit prices.' },
  ];

  LESSON_QUESTIONS['Trading']['Level 2 Data'] = [
    { type: 'multiple_choice', prompt: 'What does Level 2 data show that Level 1 data does not?', options: ['Only the company name', 'The full order book with multiple bid and ask prices and their sizes', 'Just the last trade price', 'Only the daily high and low'], correctAnswer: 'The full order book with multiple bid and ask prices and their sizes', difficulty: 'easy', explanation: 'Level 1 shows the best bid and ask. Level 2 reveals the depth of the market — all pending buy and sell orders at various price levels, showing where liquidity exists.' },
    { type: 'true_false', prompt: 'A large bid wall on Level 2 always means the stock will go up.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'Large bid walls can be spoofing — traders placing orders they intend to cancel to create a false impression of demand. They can also be pulled instantly. Never rely on Level 2 alone.' },
    { type: 'multiple_choice', prompt: 'What is "spoofing" in the context of Level 2 data?', options: ['A trading strategy using averages', 'Placing large fake orders to manipulate other traders, then canceling before execution', 'A type of limit order', 'Reading the tape'], correctAnswer: 'Placing large fake orders to manipulate other traders, then canceling before execution', difficulty: 'medium', explanation: 'Spoofing is illegal market manipulation where a trader places large orders to create the illusion of supply or demand, influencing prices, then cancels those orders before they are filled.' },
    { type: 'fill_gap', prompt: 'The "order ___" shows all pending buy and sell orders at different price levels.', options: ['Book', 'Tape', 'Flow', 'Chart'], correctAnswer: 'Book', difficulty: 'easy', explanation: 'The order book (also called the depth of market or Level 2) displays all resting limit orders, showing the available liquidity at each price level on both the buy and sell sides.' },
    { type: 'true_false', prompt: 'Hidden or "iceberg" orders do not appear in the Level 2 order book.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Iceberg orders only show a small visible portion while hiding the total size. Institutions use them to avoid revealing their full buying or selling interest to the market.' },
    { type: 'multiple_choice', prompt: 'What does it mean when the ask side of the order book is "thin"?', options: ['The stock is overvalued', 'There are few sell orders, so price can move up quickly with even modest buying', 'The market is closed', 'The stock will crash'], correctAnswer: 'There are few sell orders, so price can move up quickly with even modest buying', difficulty: 'easy', explanation: 'A thin ask side means limited selling liquidity. Even a moderate buy order can push the price up rapidly because there are few shares available to absorb the demand at nearby price levels.' },
    { type: 'multiple_choice', prompt: 'What is "depth of market" (DOM)?', options: ['How deep the stock price can fall', 'Another name for Level 2 showing order sizes at each price level', 'The total market capitalization', 'A chart type'], correctAnswer: 'Another name for Level 2 showing order sizes at each price level', difficulty: 'easy', explanation: 'Depth of market (DOM) is a visual representation of the order book. It shows the cumulative volume of buy and sell orders at each price level, helping traders gauge supply and demand.' },
    { type: 'swipe_judge', prompt: 'Using Level 2 data to identify likely support and resistance zones based on large resting orders.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Good practice', difficulty: 'medium', explanation: 'Large clusters of resting orders on Level 2 can act as short-term support (large bids) or resistance (large asks). This is a valid way to identify key price levels, though orders can always be canceled.' },
  ];

  LESSON_QUESTIONS['Trading']['Options Spreads'] = [
    { type: 'multiple_choice', prompt: 'What is an options spread?', options: ['The bid-ask gap on an option', 'A strategy that involves buying and selling options simultaneously to limit risk', 'Spreading your options across different brokers', 'A type of market order'], correctAnswer: 'A strategy that involves buying and selling options simultaneously to limit risk', difficulty: 'easy', explanation: 'An options spread combines buying and selling options of the same type (calls or puts) at different strike prices or expirations. This limits both risk and reward compared to naked options.' },
    { type: 'true_false', prompt: 'A vertical spread involves options with the same expiration but different strike prices.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Vertical spreads (also called price spreads) use the same expiration date but different strikes. A bull call spread buys a lower strike call and sells a higher strike call.' },
    { type: 'multiple_choice', prompt: 'What is a bull call spread?', options: ['Buying a call and selling a put', 'Buying a lower-strike call and selling a higher-strike call at the same expiration', 'Buying two calls at the same strike', 'Selling calls at multiple strikes'], correctAnswer: 'Buying a lower-strike call and selling a higher-strike call at the same expiration', difficulty: 'medium', explanation: 'A bull call spread is a debit spread. You pay for the lower-strike call and offset the cost by selling the higher-strike call. Max profit is the difference in strikes minus the net debit.' },
    { type: 'true_false', prompt: 'A credit spread generates income upfront because the option sold is worth more than the option bought.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'In a credit spread, you receive a net credit because the premium of the option you sell exceeds the premium of the option you buy. Your max profit is the credit received.' },
    { type: 'multiple_choice', prompt: 'What is a calendar spread?', options: ['Trading options based on the calendar year', 'Buying and selling options at the same strike but different expirations', 'A daily trading schedule', 'A spread on index futures'], correctAnswer: 'Buying and selling options at the same strike but different expirations', difficulty: 'medium', explanation: 'Calendar spreads (also called time spreads) profit from the difference in time decay rates between near-term and far-term options at the same strike price.' },
    { type: 'fill_gap', prompt: 'The maximum loss on a debit spread is the net ___ paid to enter the trade.', options: ['Premium', 'Margin', 'Commission', 'Spread'], correctAnswer: 'Premium', difficulty: 'easy', explanation: 'With a debit spread, the most you can lose is the net premium paid. This defined risk is a major advantage of spreads over buying or selling naked options.' },
    { type: 'multiple_choice', prompt: 'What is the main advantage of spreads over buying naked options?', options: ['Higher maximum profit', 'No commissions', 'Reduced cost basis and defined risk', 'Unlimited upside'], correctAnswer: 'Reduced cost basis and defined risk', difficulty: 'medium', explanation: 'Spreads lower your cost by offsetting the purchased option with a sold option. Both your maximum risk and maximum reward are defined upfront, making them easier to manage.' },
    { type: 'swipe_judge', prompt: 'Using a bull put spread to collect premium when you are moderately bullish on a stock.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Good practice', difficulty: 'hard', explanation: 'A bull put spread sells a higher-strike put and buys a lower-strike put. If the stock stays above the sold put strike, you keep the premium. This is a sound strategy for moderately bullish outlooks with defined risk.' },
  ];

  LESSON_QUESTIONS['Trading']['Covered Calls'] = [
    { type: 'multiple_choice', prompt: 'What is a covered call strategy?', options: ['Buying a call option without owning the stock', 'Owning 100 shares and selling a call option against them to generate income', 'Selling short and buying a call', 'A leveraged options strategy'], correctAnswer: 'Owning 100 shares and selling a call option against them to generate income', difficulty: 'easy', explanation: 'A covered call involves holding 100 shares and selling one call contract. You collect premium income. If the stock rises above the strike, your shares get called away at that price.' },
    { type: 'true_false', prompt: 'The main risk of a covered call is that the stock drops significantly while you hold it.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'The premium collected from selling the call provides a small buffer, but if the stock falls hard, your losses on the shares will far exceed the premium income. The downside risk is nearly the same as owning the stock.' },
    { type: 'multiple_choice', prompt: 'If you sell a covered call with a $55 strike and the stock rallies to $70, what happens?', options: ['You keep all the gains to $70', 'Nothing, the call expires', 'Your shares are likely called away at $55, and you miss the move above $55', 'You lose money on the call'], correctAnswer: 'Your shares are likely called away at $55, and you miss the move above $55', difficulty: 'medium', explanation: 'When the stock exceeds the call strike, the buyer will exercise. You must sell your 100 shares at $55 regardless of market price. You keep the premium but miss gains above $55.' },
    { type: 'true_false', prompt: 'Selling covered calls is often called a "conservative income strategy."', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Covered calls are considered conservative because you own the underlying shares. The sold call is "covered" by your stock, so there is no naked exposure. Many retirees use this to generate steady income.' },
    { type: 'fill_gap', prompt: 'To sell one standard covered call contract, you must own at least ___ shares of the underlying stock.', options: ['100', '50', '10', '1000'], correctAnswer: '100', difficulty: 'easy', explanation: 'One options contract represents 100 shares. To "cover" a sold call, you need exactly 100 shares per contract so you can deliver them if assigned.' },
    { type: 'multiple_choice', prompt: 'What strike price selection for a covered call offers the best balance of income and upside potential?', options: ['Deep in-the-money strikes', 'At-the-money strikes for maximum premium', 'Slightly out-of-the-money strikes above current price', 'Very far out-of-the-money strikes'], correctAnswer: 'Slightly out-of-the-money strikes above current price', difficulty: 'medium', explanation: 'Slightly OTM strikes offer a decent premium while still allowing some upside appreciation if the stock rises. This balances income generation with capital gains potential.' },
    { type: 'multiple_choice', prompt: 'Why is covered call writing less effective in a strongly bullish market?', options: ['The premium disappears', 'The market shuts down covered calls', 'You cap your upside and miss large rallies by having shares called away', 'It becomes too expensive'], correctAnswer: 'You cap your upside and miss large rallies by having shares called away', difficulty: 'hard', explanation: 'In a strong bull market, stocks often blow through the call strike. You collect a small premium but miss significant gains above the strike. Covered calls work best in flat to mildly bullish environments.' },
    { type: 'before_after', prompt: 'Which covered call approach is more sensible?', options: ['I sell covered calls on all my stocks every week for maximum income.', 'I sell covered calls on stable holdings in flat markets, but keep high-conviction growth stocks uncovered.'], correctAnswer: 'I sell covered calls on stable holdings in flat markets, but keep high-conviction growth stocks uncovered.', difficulty: 'medium', explanation: 'Blanket covered call writing can cap your best performers. Selectively selling calls on stable, range-bound positions while keeping high-growth positions uncovered optimizes total portfolio return.' },
  ];

  LESSON_QUESTIONS['Trading']['Iron Condor'] = [
    { type: 'multiple_choice', prompt: 'What is an iron condor?', options: ['A single option trade', 'A four-leg options strategy that profits from low volatility and range-bound price action', 'A type of candlestick pattern', 'A leveraged ETF'], correctAnswer: 'A four-leg options strategy that profits from low volatility and range-bound price action', difficulty: 'easy', explanation: 'An iron condor combines a bull put spread and a bear call spread. You sell both an OTM put and an OTM call while buying further OTM options for protection. You profit if price stays within the sold strikes.' },
    { type: 'true_false', prompt: 'An iron condor profits when the underlying stock makes a big move in either direction.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'Iron condors profit from low volatility and range-bound markets. Large moves in either direction cause losses. The strategy benefits when the stock stays between the two short strikes until expiration.' },
    { type: 'multiple_choice', prompt: 'What is the maximum profit on an iron condor?', options: ['Unlimited', 'The width of the strikes', 'The net credit received when opening the trade', 'Double the premium collected'], correctAnswer: 'The net credit received when opening the trade', difficulty: 'medium', explanation: 'Max profit equals the total premium collected from selling both spreads. This occurs when the stock expires between the two short strikes and all four options expire worthless.' },
    { type: 'true_false', prompt: 'Iron condors have defined and limited risk on both sides.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'The long wings (bought options) cap your loss on each side. Max loss equals the width of one spread minus the net credit. Risk is defined and known before entering the trade.' },
    { type: 'fill_gap', prompt: 'An iron condor consists of ___ option contracts working together.', options: ['4', '2', '3', '6'], correctAnswer: '4', difficulty: 'easy', explanation: 'An iron condor has four legs: sell an OTM put, buy a further OTM put (bull put spread), sell an OTM call, and buy a further OTM call (bear call spread).' },
    { type: 'multiple_choice', prompt: 'When is the best time to enter an iron condor?', options: ['When volatility is extremely low', 'Right before an earnings announcement when implied volatility is high', 'During a market crash', 'When the stock is trending strongly'], correctAnswer: 'Right before an earnings announcement when implied volatility is high', difficulty: 'hard', explanation: 'High implied volatility inflates option premiums, increasing the credit received. After the event, IV typically crushes, benefiting the iron condor seller. However, the event must not move price outside the strikes.' },
    { type: 'multiple_choice', prompt: 'What happens to an iron condor if the stock drops below the sold put strike?', options: ['All options expire worthless', 'You start losing money on the put side of the trade', 'The call side becomes profitable, canceling the loss', 'Nothing, the trade is protected'], correctAnswer: 'You start losing money on the put side of the trade', difficulty: 'medium', explanation: 'If the stock drops below the short put strike, the put spread moves in-the-money and you begin losing. The long put limits your loss, but the call side becoming worthless does not offset the put side loss beyond the credit received.' },
    { type: 'swipe_judge', prompt: 'Holding an iron condor through a major earnings surprise because you are "sure it will come back."', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'medium', explanation: 'If the stock gaps outside your strikes after earnings, the trade is a loser. Hoping for a reversal adds risk. Many experienced traders close or adjust before earnings or accept the defined loss and move on.' },
  ];

  LESSON_QUESTIONS['Trading']['Scalping'] = [
    { type: 'multiple_choice', prompt: 'What is scalping in trading?', options: ['Holding stocks for years', 'Making many rapid trades to capture small price movements within minutes or seconds', 'Buying stocks on sale', 'A type of fundamental analysis'], correctAnswer: 'Making many rapid trades to capture small price movements within minutes or seconds', difficulty: 'easy', explanation: 'Scalping is an ultra-short-term strategy where traders aim to profit from tiny price moves. Scalpers may execute dozens to hundreds of trades per day, holding each for seconds to minutes.' },
    { type: 'true_false', prompt: 'Scalping requires very tight spreads and low commissions to be profitable.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Since scalpers target tiny price moves (often just a few cents), transaction costs are critical. High spreads or commissions can eat up the small profits, making the strategy unprofitable.' },
    { type: 'multiple_choice', prompt: 'Why is high liquidity essential for scalping?', options: ['It makes charts look better', 'It ensures orders fill quickly at the expected price with minimal slippage', 'Liquidity is not important for scalping', 'It reduces the number of trades needed'], correctAnswer: 'It ensures orders fill quickly at the expected price with minimal slippage', difficulty: 'easy', explanation: 'Scalpers need instant execution at precise prices. Illiquid markets cause slippage (worse fill prices), which can turn a winning scalp into a loser given the razor-thin margins involved.' },
    { type: 'fill_gap', prompt: 'Scalpers typically use ___ time period charts such as 1-minute or tick charts.', options: ['Very short', 'Daily', 'Weekly', 'Monthly'], correctAnswer: 'Very short', difficulty: 'easy', explanation: 'Scalpers operate on the shortest timeframes: tick charts, 1-second, or 1-minute charts. These granular views let them spot micro price movements and order flow patterns.' },
    { type: 'true_false', prompt: 'A scalper can be profitable even with a win rate below 50% if the average win is larger than the average loss.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Profitability depends on both win rate and risk/reward ratio. A scalper winning 40% of the time but with wins averaging 2x the size of losses will be profitable over many trades.' },
    { type: 'multiple_choice', prompt: 'What is the biggest psychological challenge of scalping?', options: ['Boredom from waiting', 'Decision fatigue and emotional burnout from constant rapid decision-making', 'Understanding fundamentals', 'Learning chart patterns'], correctAnswer: 'Decision fatigue and emotional burnout from constant rapid decision-making', difficulty: 'medium', explanation: 'Scalping demands constant focus and split-second decisions. The mental intensity causes fatigue that leads to mistakes. Most scalpers limit sessions to 2-3 hours to maintain peak performance.' },
    { type: 'multiple_choice', prompt: 'What role does "Level 2" data play in scalping?', options: ['It is irrelevant to scalpers', 'It helps scalpers see pending order sizes to anticipate short-term supply and demand shifts', 'It shows annual financial reports', 'It only matters for long-term investors'], correctAnswer: 'It helps scalpers see pending order sizes to anticipate short-term supply and demand shifts', difficulty: 'medium', explanation: 'Scalpers heavily rely on Level 2 to see where large orders are resting. A big bid may act as short-term support, while a large ask signals resistance. This informs split-second entry and exit decisions.' },
    { type: 'swipe_judge', prompt: 'Scalping a stock during the low-volume lunch hour (12:00-1:30 PM ET).', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'medium', explanation: 'The lunch hour typically has low volume and choppy, directionless price action. Scalpers prefer the first and last hours of the trading day when volume and volatility are highest.' },
  ];

  LESSON_QUESTIONS['Trading']['Mean Reversion'] = [
    { type: 'multiple_choice', prompt: 'What is mean reversion in trading?', options: ['Prices always go to zero', 'The theory that prices tend to return to their average or historical mean over time', 'A type of stop-loss', 'Following the trend indefinitely'], correctAnswer: 'The theory that prices tend to return to their average or historical mean over time', difficulty: 'easy', explanation: 'Mean reversion is the concept that prices and returns eventually move back toward their long-term average. Extreme moves tend to be temporary, and assets gravitate toward their mean.' },
    { type: 'true_false', prompt: 'Bollinger Bands can be used to identify mean reversion opportunities.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'When price touches or exceeds the outer Bollinger Bands (2 standard deviations from the mean), it is statistically extended. Mean reversion traders look to trade the snap-back toward the middle band (the moving average).' },
    { type: 'multiple_choice', prompt: 'Which indicator is commonly used by mean reversion traders to identify overbought or oversold conditions?', options: ['Moving average', 'Volume', 'RSI (Relative Strength Index)', 'Ichimoku Cloud'], correctAnswer: 'RSI (Relative Strength Index)', difficulty: 'easy', explanation: 'RSI above 70 indicates overbought conditions and RSI below 30 indicates oversold conditions. Mean reversion traders look to sell overbought assets and buy oversold ones, expecting a return to normal levels.' },
    { type: 'true_false', prompt: 'Mean reversion strategies work best in trending markets with strong momentum.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'Mean reversion works best in range-bound or choppy markets. In strong trends, prices can stay "extended" for far longer than expected, causing mean reversion trades to fail repeatedly.' },
    { type: 'fill_gap', prompt: 'A stock trading 3 standard deviations above its 20-day average is considered statistically ___.', options: ['Extended', 'Normal', 'Cheap', 'Stable'], correctAnswer: 'Extended', difficulty: 'medium', explanation: 'Being 3 standard deviations from the mean is statistically rare (less than 1% of the time in a normal distribution). Such extreme extension often precedes a reversion toward the average.' },
    { type: 'multiple_choice', prompt: 'What is the biggest risk of mean reversion trading?', options: ['Markets are always mean reverting', 'The asset enters a strong trend and never reverts, causing large losses', 'It requires too many indicators', 'It only works on daily charts'], correctAnswer: 'The asset enters a strong trend and never reverts, causing large losses', difficulty: 'medium', explanation: 'Sometimes what looks like an overextension is actually the start of a new trend. Buying a falling stock expecting reversion can result in catching a falling knife if fundamentals have changed.' },
    { type: 'multiple_choice', prompt: 'What is a "Z-score" and how do mean reversion traders use it?', options: ['A type of chart pattern', 'A measure of how many standard deviations the current price is from the mean', 'The final score of a trading day', 'A risk management ratio'], correctAnswer: 'A measure of how many standard deviations the current price is from the mean', difficulty: 'hard', explanation: 'Z-score quantifies how far price has deviated from the mean in standard deviations. A Z-score above +2 or below -2 signals a statistically significant deviation, offering potential mean reversion entry points.' },
    { type: 'before_after', prompt: 'Which mean reversion approach is better?', options: ['The stock dropped 20% — it\'s oversold, buying blindly for the bounce.', 'The stock dropped 20%, RSI is at 25, and price is at a historical support level — entering with a defined stop-loss.'], correctAnswer: 'The stock dropped 20%, RSI is at 25, and price is at a historical support level — entering with a defined stop-loss.', difficulty: 'hard', explanation: 'Successful mean reversion requires confluence: multiple indicators confirming the extreme, a clear support level, and always a defined stop-loss in case reversion does not occur.' },
  ];

  LESSON_QUESTIONS['Trading']['Momentum Trading'] = [
    { type: 'multiple_choice', prompt: 'What is momentum trading?', options: ['Buying stocks that are falling', 'A strategy that buys assets showing strong upward price trends and sells those showing weakness', 'Holding stocks for decades', 'Only trading on Mondays'], correctAnswer: 'A strategy that buys assets showing strong upward price trends and sells those showing weakness', difficulty: 'easy', explanation: 'Momentum trading follows Newton\'s law applied to markets: assets in motion tend to stay in motion. Traders buy stocks making new highs and exhibiting strong price trends, riding the wave.' },
    { type: 'true_false', prompt: 'Momentum and mean reversion are opposite trading approaches.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Momentum traders buy strength and sell weakness (trend following), while mean reversion traders buy weakness and sell strength (expecting a snap-back). They are fundamentally opposite approaches.' },
    { type: 'multiple_choice', prompt: 'Which technical indicator is specifically designed to measure momentum?', options: ['Bollinger Bands', 'Support and resistance lines', 'MACD (Moving Average Convergence Divergence)', 'Pivot points'], correctAnswer: 'MACD (Moving Average Convergence Divergence)', difficulty: 'easy', explanation: 'MACD measures the relationship between two moving averages and includes a signal line and histogram that directly show momentum changes, making it one of the most popular momentum indicators.' },
    { type: 'true_false', prompt: 'Stocks making new 52-week highs tend to outperform stocks making new 52-week lows over the following months.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Academic research consistently shows that stocks with strong recent performance continue to outperform in the short to medium term. This "momentum effect" is one of the most well-documented market anomalies.' },
    { type: 'fill_gap', prompt: 'The momentum strategy mantra is "buy high, sell ___."', options: ['Higher', 'Low', 'Even', 'Fast'], correctAnswer: 'Higher', difficulty: 'easy', explanation: 'Unlike value investing (buy low, sell high), momentum trading buys stocks already moving up and sells them at even higher prices. The goal is to ride the trend, not to find bargains.' },
    { type: 'multiple_choice', prompt: 'What is the main risk of momentum trading?', options: ['It is too slow', 'Sharp reversals can cause rapid losses when momentum suddenly stalls', 'It requires too little attention', 'It only works in bear markets'], correctAnswer: 'Sharp reversals can cause rapid losses when momentum suddenly stalls', difficulty: 'medium', explanation: 'Momentum stocks can reverse violently when the trend breaks. The same force that pushed prices up quickly reverses, and crowded momentum trades unwind rapidly as everyone rushes for the exit simultaneously.' },
    { type: 'multiple_choice', prompt: 'What is "relative strength" in momentum trading?', options: ['The RSI indicator', 'Comparing a stock\'s performance against a benchmark or other stocks to find the strongest performers', 'Physical strength required for trading', 'The strength of support levels'], correctAnswer: 'Comparing a stock\'s performance against a benchmark or other stocks to find the strongest performers', difficulty: 'medium', explanation: 'Relative strength compares one stock\'s performance to others or to an index. Stocks outperforming their peers show strong relative strength and are prime momentum candidates. This is different from the RSI indicator.' },
    { type: 'swipe_judge', prompt: 'Chasing a stock that has already run up 100% in a week with no pullback.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'Even in momentum trading, chasing parabolic moves is dangerous. The best momentum entries come on pullbacks within an uptrend, not after a stock is already overextended and likely due for a correction.' },
  ];

  LESSON_QUESTIONS['Trading']['Intermarket Analysis'] = [
    { type: 'multiple_choice', prompt: 'What is intermarket analysis?', options: ['Analyzing only one market', 'Studying the relationships between stocks, bonds, commodities, and currencies to find trading signals', 'International marketing analysis', 'Comparing different brokers'], correctAnswer: 'Studying the relationships between stocks, bonds, commodities, and currencies to find trading signals', difficulty: 'easy', explanation: 'Intermarket analysis examines how different asset classes influence each other. For example, rising interest rates affect bond prices, which impact stocks, which influence currencies. Understanding these links gives a broader market perspective.' },
    { type: 'true_false', prompt: 'Bond prices and interest rates move in opposite directions.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'When interest rates rise, existing bond prices fall because new bonds offer higher yields. Conversely, when rates drop, existing bonds become more valuable. This inverse relationship is fundamental to intermarket analysis.' },
    { type: 'multiple_choice', prompt: 'What is the typical relationship between the US Dollar and commodity prices?', options: ['They always move together', 'A stronger dollar tends to push commodity prices lower', 'They are completely unrelated', 'Commodities control the dollar'], correctAnswer: 'A stronger dollar tends to push commodity prices lower', difficulty: 'medium', explanation: 'Most commodities are priced in US dollars. When the dollar strengthens, commodities become more expensive for foreign buyers, reducing demand and pushing prices lower. This inverse correlation is a key intermarket relationship.' },
    { type: 'fill_gap', prompt: 'When investors sell stocks and buy Treasury bonds during uncertainty, it is called a "flight to ___."', options: ['Safety', 'Risk', 'Profit', 'Yield'], correctAnswer: 'Safety', difficulty: 'easy', explanation: 'Flight to safety occurs when investors move capital from risky assets (stocks) to safer ones (government bonds, gold) during market turmoil. This rotation causes bond prices to rise and stock prices to fall simultaneously.' },
    { type: 'true_false', prompt: 'Rising oil prices can be a leading indicator of inflation, which eventually affects stock valuations.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Oil is a key input cost for most industries. Rising oil prices increase production and transportation costs, feeding through to consumer prices (inflation). Central banks then raise rates to fight inflation, which pressures stock valuations.' },
    { type: 'multiple_choice', prompt: 'What does the VIX (Volatility Index) measure and how does it relate to stocks?', options: ['The value of tech stocks', 'Expected market volatility, and it typically rises sharply when stocks fall', 'Trading volume on the NYSE', 'Currency exchange rates'], correctAnswer: 'Expected market volatility, and it typically rises sharply when stocks fall', difficulty: 'medium', explanation: 'The VIX, known as the "fear gauge," measures expected S&P 500 volatility from options prices. It typically spikes during market sell-offs and declines during calm rallies, making it a useful contrarian and hedging tool.' },
    { type: 'multiple_choice', prompt: 'Why might a gold rally alongside falling bond yields signal trouble for stocks?', options: ['Gold and stocks always move together', 'It suggests investors are seeking safe havens, expecting economic weakness or market decline', 'It means the economy is booming', 'Gold has no relationship to other markets'], correctAnswer: 'It suggests investors are seeking safe havens, expecting economic weakness or market decline', difficulty: 'hard', explanation: 'Gold rising with bond yields falling (bond prices rising) signals a simultaneous flight to safety. Smart money is rotating out of risk assets and into defensive positions, often preceding a stock market decline.' },
    { type: 'swipe_judge', prompt: 'Ignoring what the bond market is signaling when making stock trading decisions.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'The bond market is often called "the smart money market" and tends to lead stocks. Ignoring signals from bonds, yields, and the yield curve means missing critical early warnings about economic direction.' },
  ];

  LESSON_QUESTIONS['Trading']['Economic Indicators'] = [
    { type: 'multiple_choice', prompt: 'What is GDP (Gross Domestic Product)?', options: ['A stock market index', 'The total value of goods and services produced by a country over a specific period', 'A type of trading order', 'A measure of inflation'], correctAnswer: 'The total value of goods and services produced by a country over a specific period', difficulty: 'easy', explanation: 'GDP is the broadest measure of economic health. Two consecutive quarters of negative GDP growth is the technical definition of a recession, which significantly impacts stock markets.' },
    { type: 'true_false', prompt: 'The Non-Farm Payrolls (NFP) report is released on the first Friday of every month and often causes high market volatility.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'NFP is one of the most market-moving economic reports. It measures jobs added or lost in the US economy (excluding farms). Surprises versus expectations can cause massive intraday swings in stocks, bonds, and currencies.' },
    { type: 'multiple_choice', prompt: 'What does the Consumer Price Index (CPI) measure?', options: ['Stock prices', 'Consumer confidence', 'The average change in prices paid by consumers for goods and services (inflation)', 'Corporate profits'], correctAnswer: 'The average change in prices paid by consumers for goods and services (inflation)', difficulty: 'easy', explanation: 'CPI is the primary inflation gauge. Rising CPI means consumers pay more, which pressures the Fed to raise rates. Hot CPI readings can tank stocks as traders price in tighter monetary policy.' },
    { type: 'true_false', prompt: 'A "leading" economic indicator predicts future economic activity, while a "lagging" indicator confirms past trends.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'Leading indicators (building permits, stock market, yield curve) predict where the economy is headed. Lagging indicators (unemployment rate, CPI) confirm what has already happened. Traders focus on leading indicators.' },
    { type: 'fill_gap', prompt: 'The unemployment rate is considered a ___ economic indicator because it changes after the economy has already shifted.', options: ['Lagging', 'Leading', 'Coincident', 'Forward'], correctAnswer: 'Lagging', difficulty: 'medium', explanation: 'Unemployment peaks well after a recession begins and falls well after recovery starts. By the time unemployment data improves, the stock market has often already rallied significantly.' },
    { type: 'multiple_choice', prompt: 'What is the PMI (Purchasing Managers Index) and what does a reading above 50 indicate?', options: ['A stock price target', 'A survey of manufacturing managers where above 50 signals economic expansion', 'A type of moving average', 'A central bank tool'], correctAnswer: 'A survey of manufacturing managers where above 50 signals economic expansion', difficulty: 'medium', explanation: 'PMI surveys purchasing managers on new orders, production, and employment. Above 50 = expansion, below 50 = contraction. PMI is a leading indicator that often moves before GDP data.' },
    { type: 'multiple_choice', prompt: 'Why do markets often move in the opposite direction of what economic data suggests?', options: ['Markets are irrational', 'Markets price in expectations, so the actual data only matters relative to what was expected', 'The data is always wrong', 'Traders ignore economic data'], correctAnswer: 'Markets price in expectations, so the actual data only matters relative to what was expected', difficulty: 'hard', explanation: 'Markets are forward-looking. If GDP is expected to grow 2% and it grows 1.8%, stocks may fall despite positive growth because the result missed expectations. "Buy the rumor, sell the news" reflects this dynamic.' },
    { type: 'swipe_judge', prompt: 'Trading during major economic releases like NFP without a defined plan or stop-loss.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'Economic releases cause extreme volatility and slippage. Without a plan, you are gambling on a coin flip. Many professional traders either sit out major releases or use defined-risk options strategies.' },
  ];

  LESSON_QUESTIONS['Trading']['Central Banks & Fed'] = [
    { type: 'multiple_choice', prompt: 'What is the Federal Reserve\'s primary tool for influencing the economy?', options: ['Printing money directly for consumers', 'Setting the federal funds rate (interest rate)', 'Buying and selling individual stocks', 'Setting stock market trading hours'], correctAnswer: 'Setting the federal funds rate (interest rate)', difficulty: 'easy', explanation: 'The Fed sets the federal funds rate, which is the rate banks charge each other for overnight lending. This rate ripples through the entire economy, affecting mortgages, business loans, and ultimately stock valuations.' },
    { type: 'true_false', prompt: 'When the Federal Reserve raises interest rates, it is generally negative for stock prices in the short term.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'easy', explanation: 'Higher rates increase borrowing costs for companies, reduce future earnings in discounted cash flow models, and make bonds more attractive relative to stocks. All three factors pressure stock prices downward.' },
    { type: 'multiple_choice', prompt: 'What is "quantitative easing" (QE)?', options: ['Reducing taxes', 'The central bank purchasing government bonds and other assets to inject money into the economy', 'A type of trading strategy', 'Easing trading regulations'], correctAnswer: 'The central bank purchasing government bonds and other assets to inject money into the economy', difficulty: 'medium', explanation: 'QE is an unconventional monetary policy where the central bank buys assets to increase money supply and lower long-term interest rates. This stimulates borrowing, spending, and investment, and tends to boost asset prices.' },
    { type: 'true_false', prompt: 'The "dot plot" released by the Fed shows individual committee members\' projections for future interest rates.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'The dot plot is released quarterly and shows where each FOMC member expects the federal funds rate to be in coming years. Traders scrutinize it for clues about the pace and direction of future rate changes.' },
    { type: 'fill_gap', prompt: 'The phrase "Don\'t fight the ___" means traders should not bet against central bank policy.', options: ['Fed', 'Market', 'Trend', 'News'], correctAnswer: 'Fed', difficulty: 'easy', explanation: '"Don\'t fight the Fed" is a classic trading maxim. When the Fed is easing (cutting rates, doing QE), fighting the resulting bullish trend is risky. When the Fed is tightening, being aggressively bullish is dangerous.' },
    { type: 'multiple_choice', prompt: 'What is "forward guidance" in central banking?', options: ['Predicting stock prices', 'Communication by the central bank about the likely future path of monetary policy', 'A type of technical analysis', 'Trading advice from the Fed'], correctAnswer: 'Communication by the central bank about the likely future path of monetary policy', difficulty: 'easy', explanation: 'Forward guidance is the Fed communicating its intentions to manage market expectations. Phrases like "higher for longer" or "data dependent" signal policy direction and can move markets as much as actual rate changes.' },
    { type: 'multiple_choice', prompt: 'What is an inverted yield curve and why do traders watch it?', options: ['A bullish chart pattern', 'When short-term bond yields exceed long-term yields, historically predicting recessions', 'A type of options strategy', 'When stock prices invert'], correctAnswer: 'When short-term bond yields exceed long-term yields, historically predicting recessions', difficulty: 'hard', explanation: 'Normally, long-term bonds yield more than short-term ones. An inversion means the market expects rates to fall (due to economic weakness). An inverted yield curve has preceded every US recession in the last 50 years.' },
    { type: 'before_after', prompt: 'Which approach to Fed announcements is better?', options: ['The Fed is raising rates, I\'m selling everything right now!', 'The Fed raised rates as expected — the market already priced this in. I\'ll watch the press conference for new signals about future policy.'], correctAnswer: 'The Fed raised rates as expected — the market already priced this in. I\'ll watch the press conference for new signals about future policy.', difficulty: 'medium', explanation: 'Markets price in expected rate changes well in advance. The actual announcement rarely surprises. What moves markets is the tone of the press conference and any shifts in forward guidance about future policy.' },
  ];

  LESSON_QUESTIONS['Trading']['Trading Automation'] = [
    { type: 'multiple_choice', prompt: 'What is a trading bot?', options: ['A robot that physically presses trade buttons', 'Software that automatically executes trades based on predefined rules and algorithms', 'A social media bot that posts trading tips', 'An AI that guarantees profits'], correctAnswer: 'Software that automatically executes trades based on predefined rules and algorithms', difficulty: 'easy', explanation: 'Trading bots are programs that monitor markets and execute trades when specific conditions are met. They remove emotion from trading and can operate 24/7, but they are only as good as their underlying strategy.' },
    { type: 'true_false', prompt: 'Automated trading removes all risk from trading.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: 'Automation removes emotional risk but introduces technical risks: bugs, connectivity failures, market conditions the algorithm was not designed for, and over-optimization. Automated systems still require monitoring and risk management.' },
    { type: 'multiple_choice', prompt: 'What is "backtesting" in the context of trading automation?', options: ['Testing your internet speed', 'Running a trading strategy against historical data to evaluate its past performance', 'Testing after the market closes', 'A backup testing procedure'], correctAnswer: 'Running a trading strategy against historical data to evaluate its past performance', difficulty: 'easy', explanation: 'Backtesting simulates how a strategy would have performed using historical price data. While past performance does not guarantee future results, it helps identify strategies that had an edge historically.' },
    { type: 'true_false', prompt: 'A strategy that performs exceptionally well in backtesting will always perform well in live trading.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'medium', explanation: 'Overfitting (curve-fitting) is a major risk: strategies can be optimized to perfectly fit historical data but fail in live markets. Slippage, commissions, and changing market conditions also degrade live performance.' },
    { type: 'fill_gap', prompt: 'The practice of excessively optimizing a strategy to fit historical data, causing poor live performance, is called ___.', options: ['Overfitting', 'Underfitting', 'Backtesting', 'Frontrunning'], correctAnswer: 'Overfitting', difficulty: 'medium', explanation: 'Overfitting occurs when a strategy has too many parameters tuned to past data. It captures noise instead of genuine market patterns. Overfitted strategies look amazing in backtests but fail with real money.' },
    { type: 'multiple_choice', prompt: 'What is "paper trading" and why is it important for automation?', options: ['Trading paper commodities', 'Simulated trading with fake money to test strategies in real-time market conditions without risk', 'Writing trading plans on paper', 'A type of order'], correctAnswer: 'Simulated trading with fake money to test strategies in real-time market conditions without risk', difficulty: 'easy', explanation: 'Paper trading bridges the gap between backtesting and live trading. It tests your bot in real market conditions with live data but without risking capital, revealing execution issues that backtests miss.' },
    { type: 'multiple_choice', prompt: 'What is "latency" and why does it matter in automated trading?', options: ['The time delay between signal generation and order execution, which affects fill quality', 'How late you start trading each day', 'The time between market open and close', 'Account registration delay'], correctAnswer: 'The time delay between signal generation and order execution, which affects fill quality', difficulty: 'hard', explanation: 'Latency is the delay between when your algorithm decides to trade and when the order executes. In fast markets, even milliseconds of delay can mean worse fill prices, turning profitable signals into losers.' },
    { type: 'swipe_judge', prompt: 'Deploying an automated trading bot with real money without first paper trading it.', options: ['Good practice', 'Bad practice'], correctAnswer: 'Bad practice', difficulty: 'easy', explanation: 'Going live without paper trading is reckless. Bugs, unexpected market conditions, and execution issues can cause rapid losses. Always validate with paper trading, then start live with small position sizes.' },
  ];

